export const QUESTIONS: Question[] = [
  // ─── HISTOIRE───────────────────────────────────────────────────────────────────
  { id: "h01", theme: "histoire", question: "Pouvez-vous citer trois sujets d'actualité récents en France qui vous ont particulièrement marqué ?", answer: "Trois sujets qui m'ont marqué récemment : 1. La condamnation de Marine Le Pen en 2025 à 5 ans d'inéligibilité pour détournement de fonds européens, une décision judiciaire historique. 2. La nomination de Sébastien Lecornu comme Premier ministre en octobre 2025, après une période d'instabilité gouvernementale. 3. Les tensions autour du budget 2026 et les débats sur la maîtrise du déficit public, qui touche directement la vie des Français." },
  { id: "h02", theme: "histoire", question: "Quel est le rôle de la liberté d’expression en France ?", answer: "La liberté d’expression est un droit fondamental inscrit dans la Déclaration des Droits de l’Homme et du Citoyen de 1789, permettant à chacun d’exprimer ses opinions dans le respect de la loi." },
  { id: "h03", theme: "histoire", question: "Quels blocs politiques se sont démarqués lors de ces élections ?", answer: "Les élections ont été marquées par l’avancée de trois grands blocs : le Rassemblement National (RN), la coalition pro-présidentielle (Ensemble) et le Nouveau Front Populaire, représentant la gauche. Le RN, qui a remporté le plus de voix au premier tour." },
  { id: "h04", theme: "histoire", question: "Que signifie la Liberté ?", answer: "Selon l’article 1 de la Déclaration des Droits de l'Homme et du Citoyen d'août 1789 : tous les individus naissent libres et égaux en droits, garantissant ainsi la liberté de chaque citoyen français, qu'il soit homme ou femme." },
  { id: "h05", theme: "histoire", question: "Que signifie l'Égalité?", answer: "Conformément à l'article 1 de la Déclaration des Droits de l'Homme et du Citoyen, la France garantit à tous ses citoyens une égalité juridique, leur assurant les mêmes droits, les mêmes devoirs et leur soumission aux mêmes règles." },
  { id: "h06", theme: "histoire", question: "Un exemple d’illustration de la Fraternité ?", answer: "Depuis 1945, le système de sécurité sociale, financé par les entreprises et tous ceux qui travaillent en France, incarne cette volonté de fraternité envers les concitoyens. Le pays condamne les discriminations, qui consistent à défavoriser un individu ou un groupe par rapport à d'autres, et considère le racisme comme un délit." },
  { id: "h07", theme: "histoire", question: "Quand la France est devenue laïque ?", answer: "La loi de séparation des Églises et de l'État a été adoptée le 9 décembre 1905, établissant la laïcité comme principe fondamental de la République.", date: "9 décembre 1905", president: "Émile Combes (Pdt du Conseil)" },
  { id: "h08", theme: "histoire", question: "Que signifie chaque couleur:", answer: "Le blanc est la couleur historique des rois de France, le bleu et le rouge représentent la ville de Paris." },
  { id: "h09", theme: "histoire", question: "Quelle est L'hymne national française ?", answer: "L'hymne national français est La Marseillaise. Il s'agit d'un chant révolutionnaire écrit par Claude Joseph Rouget de L’Isle en 1792. Il est devenu l'hymne officiel de la France en 1795. La Marseillaise est un symbole de la lutte pour la liberté, l'égalité et la fraternité, ainsi que de la résistance et du patriotisme." },
  { id: "h10", theme: "histoire", question: "Que représente Le 14 juillet ?", answer: "Le 14 juillet est la fête nationale française, également connue sous le nom de Bastille Day. Elle commémore la prise de la Bastille le 14 juillet 1789, qui marque le début de la Révolution française. Le 14 juillet est un symbole de la lutte pour la liberté et l'établissement de la République en France." },
  { id: "h11", theme: "histoire", question: "En quelle année le droit de vote des hommes a-t-il été introduit en France ?", answer: "Le droit de vote des hommes a été introduit en 1848, pendant la Deuxième République, avec le suffrage universel masculin." },
  { id: "h12", theme: "histoire", question: "Pouvez-vous nommer quelques ministres actuels du gouvernement français avec leur nom ?", answer: "Gouvernement Lecornu (depuis octobre 2025, remanié en février 2026) : M. Sébastien Lecornu : Premier ministre. M. Laurent Nunez : Ministre de l'Intérieur. M. Gérald Darmanin : Ministre de la Justice. M. Jean-Noël Barrot : Ministre des Affaires étrangères. Mme Catherine Vautrin : Ministre des Armées. M. Roland Lescure : Ministre de l'Économie et des Finances. Mme Annie Genevard : Ministre de l'Agriculture. M. Philippe Tabarot : Ministre des Transports. M. Vincent Jeanbrun : Ministre du Logement. Mme Catherine Pégard : Ministre de la Culture. M. Philippe Baptiste : Ministre de l'Enseignement supérieur. (Source : gouvernement.fr)" },
  { id: "h13", theme: "histoire", question: "C'est quoi le suffrage universel ?", answer: "Le suffrage universel est un système de vote où tous les citoyens adultes, sans distinction de sexe, de richesse ou de statut, ont le droit de participer aux élections. En France, il est utilisé pour élire les députés, le président de la République et d'autres représentants." },
  { id: "h14", theme: "histoire", question: "Quel document établit les droits fondamentaux des citoyens français ?", answer: "La Constitution de la Ve République." },
  { id: "h15", theme: "histoire", question: "Qui était le général Charles de Gaulle ?", answer: "Leader de la France libre pendant la Seconde Guerre mondiale et premier président de la Ve République." },
  { id: "h16", theme: "histoire", question: "Quel est le principe du droit du sol en matière de nationalité française ?", answer: "Le fait d'acquérir la nationalité française par la naissance en France, sous certaines conditions." },
  { id: "h17", theme: "histoire", question: "Quelles sont les causes principales de la Révolution française ?", answer: "La Révolution française (1789-1799) a été causée par plusieurs facteurs:  Une crise financière due aux dépenses excessives de la monarchie et aux guerres, notamment la guerre d’indépendance américaine." },
  { id: "h18", theme: "histoire", question: "Quelles sont les dates clés de la Révolution française ?", answer: " 5 mai 1789 : Ouverture des États généraux par Louis XVI (16).  17 juin 1789 : Le tiers état se proclame Assemblée nationale.  20 juin 1789 : Serment du Jeu de Paume, engagement de donner une constitution à la France.  14 juillet 1789 : Prise de la Bastille, symbole du début de la Révolution." },
  { id: "h19", theme: "histoire", question: "Qu'est-ce que l'ouverture des États généraux ?", answer: "L’ouverture des États généraux a eu lieu le 5 mai 1789 à Versailles. C’était une réunion convoquée par le roi Louis XVI (16) pour tenter de résoudre la grave crise financière que traversait la France." },
  { id: "h20", theme: "histoire", question: "quel était le résultat de cette ouverture ?", answer: "Chaque ordre devait exprimer ses doléances (revendications) durant cette réunion. Le Tiers-État, frustré par l'injustice du système de vote, se proclame Assemblée nationale le 17 juin 1789, marquant ainsi le début de la Révolution française." },
  { id: "h21", theme: "histoire", question: "Citez Quelques événements marquants de la Révolution ?", answer: " La Nuit du 4 août 1789 : Abolition des privilèges et des droits féodaux.  La Constitution de 1791 : Instauration d’une monarchie constitutionnelle.  La République proclamée le 22 septembre 1792 : Fin de la monarchie, début de la Première République." },
  { id: "h22", theme: "histoire", question: "Qui sont les principales figures de la Révolution ?", answer: " Louis XVI (1754-1793) : Roi de France exécuté en 1793.  Marie-Antoinette (1755-1793) : Reine de France, guillotinée.  Mirabeau (1749-1791) : Orateur influent du début de la Révolution.  Robespierre (1758-1794) : Chef des Jacobins, instigateur de la Terreur.  Danton (1759-1794) : Révolutionnaire modéré, exécuté sous la Terreur." },
  { id: "h23", theme: "histoire", question: "Quelle est l'année de début de la Révolution Française ?", answer: "La Révolution Française, marquant une transformation profonde de la société et du gouvernement en France, a débuté en 1789. Elle est célèbre pour ses idéaux de liberté, d'égalité et de fraternité et a conduit à la chute de la monarchie absolue." },
  { id: "h24", theme: "histoire", question: "Quel monarque régnait en France au début de la Révolution Française ?", answer: "Louis XVI (16) était le roi de France au début de la Révolution. Son règne est souvent associé à la montée des tensions sociales et économiques qui ont mené à la Révolution." },
  { id: "h25", theme: "histoire", question: "Pourquoi célèbre-t-on le 14 juillet en France ?", answer: "Le 14 juillet, connu comme la Fête Nationale française, commémore la prise de la Bastille en 1789, un événement symbolique de la lutte contre l'oppression et un tournant majeur de la Révolution Française." },
  { id: "h26", theme: "histoire", question: "Quel était le rôle initial de la Bastille à Paris ?", answer: "La Bastille, initialement construite comme une forteresse pour protéger Paris, était devenue une prison d'État avant la Révolution Française. Sa prise par les révolutionnaires est devenue un symbole fort de la lutte contre l'autoritarisme." },
  { id: "h27", theme: "histoire", question: "Pourquoi la prise de la Bastille est-elle un symbole fort ?", answer: "La Bastille était une prison royale symbolisant l’absolutisme du roi. Sa prise le 14 juillet 1789 marque le début de la Révolution et la révolte du peuple contre l’autorité monarchique." },
  { id: "h28", theme: "histoire", question: "Pourquoi la Révolution a-t-elle conduit à l’exécution du roi Louis XVI ?", answer: "Après sa tentative de fuite en 1791, Louis XVI est perçu comme un traître. Il est jugé pour trahison et condamné à mort par la Convention en janvier 1793." },
  { id: "h29", theme: "histoire", question: "Quelles sont les principales réformes de la Révolution ?", answer: " Abolition des privilèges et des droits féodaux (4 août 1789).  Déclaration des Droits de l’Homme et du Citoyen (26 août 1789).  Constitution de 1791 instaurant une monarchie constitutionnelle.  Création du suffrage universel masculin en 1792.  Instauration du calendrier républicain (1793-1805)." },
  { id: "h30", theme: "histoire", question: "Quand et pourquoi la Première République a-t-elle été proclamée ?", answer: "Elle a été proclamée le 21 septembre 1792 après la chute de la monarchie. La fuite du roi en 1791 et son procès pour trahison ont contribué à son abolition." },
  { id: "h31", theme: "histoire", question: "Quel événement marque la fin officielle de la monarchie ?", answer: "La Convention nationale a voté l'abolition de la monarchie le 21 septembre 1792, mettant fin au règne de Louis XVI (16)." },
  { id: "h32", theme: "histoire", question: "Comment Louis XVI (16) a-t-il été jugé ?", answer: "Il a été jugé par la Convention nationale, reconnu coupable de trahison et guillotiné le 21 janvier 1793." },
  { id: "h33", theme: "histoire", question: "Quels étaient les pouvoirs sous la Première République ?", answer: " La Convention nationale (1792-1795), qui gouvernait et adoptait les lois.  Le Comité de salut public (1793-1794), dirigé par Robespierre, qui a exercé un pouvoir fort pendant la Terreur.  Le Directoire (1795-1799), un gouvernement plus modéré avec cinq directeurs." },
  { id: "h34", theme: "histoire", question: "Pourquoi la Terreur a-t-elle eu lieu ?", answer: "Entre 1793 et 1794, le gouvernement a instauré la Terreur pour éliminer les ennemis de la Révolution. Environ 16 000 personnes ont été exécutées sous l'autorité du Comité de salut public, dirigé par Robespierre." },
  { id: "h35", theme: "histoire", question: "Qu'est-ce que le Directoire ?", answer: "Le Directoire (1795-1799) était un régime plus modéré, dirigé par cinq directeurs, mais il était instable et affaibli par la corruption." },
  { id: "h36", theme: "histoire", question: "Qu'est-ce que le Consulat en France ?", answer: "Le Consulat a été une période de gouvernement en France après la Révolution, de 1799 à 1804. Dirigé par Napoléon Bonaparte en tant que Premier Consul, il a marqué la fin de la Révolution et a conduit à l'établissement du Premier Empire français." },
  { id: "h37", theme: "histoire", question: "Comment Napoléon Bonaparte a-t-il pris le pouvoir ?", answer: "Par le coup d'État du (9 novembre 1799), où il renverse le Directoire avec l’aide de l'armée et instaure un nouveau régime." },
  { id: "h38", theme: "histoire", question: "Quel régime Napoléon met-il en place après le coup d'État ?", answer: "Il met en place le Consulat (1799-1804), où il gouverne avec deux autres consuls, mais il devient rapidement le seul dirigeant." },
  { id: "h39", theme: "histoire", question: "Quelles sont les principales réformes de Napoléon sous le Consulat ?", answer: " Création des préfets pour administrer les départements.  Réforme de l'éducation avec les lycées.  Création du franc germinal (monnaie stable).  Adoption du Code civil (1804), qui influence encore le droit français." },
  { id: "h40", theme: "histoire", question: "Quand la Première République prend-elle fin?", answer: "Le 2 décembre 1804, Napoléon Bonaparte se fait sacrer Empereur des Français, mettant fin à la Première République et établissant le Premier Empire." },
  { id: "h41", theme: "histoire", question: "Quand et pourquoi la Deuxième République a-t-elle été proclamée ?", answer: "Elle est proclamée le 24 février 1848, après la révolution de février qui entraîne l'abdication du roi Louis-Philippe Ier et la fin de la monarchie de Juillet." },
  { id: "h42", theme: "histoire", question: "Quelles sont les premières grandes mesures de la Deuxième République ?", answer: " Établissement du suffrage universel masculin (27 millions de citoyens peuvent voter).  Abolition définitive de l'esclavage dans les colonies françaises (27 avril 1848, sous l'impulsion de Victor Schœlcher).  Création des Ateliers nationaux pour fournir du travail aux ouvriers (abandonnés après peu de temps)." },
  { id: "h43", theme: "histoire", question: "Qui est élu premier président de la République ?", answer: "Louis-Napoléon Bonaparte, élu au suffrage universel masculin le 10 décembre 1848 avec 74% des voix." },
  { id: "h44", theme: "histoire", question: "Comment la Deuxième République prend-elle fin ?", answer: "Par le coup d'État du 2 décembre 1851, où Louis-Napoléon Bonaparte dissout l’Assemblée nationale et établit un pouvoir personnel." },
  { id: "h45", theme: "histoire", question: "Que devient la France après la Deuxième République ?", answer: "Un an après son coup d’État, Louis-Napoléon Bonaparte se fait proclamer empereur sous le nom de Napoléon III, marquant le début du Second Empire (1852-1870)." },
  { id: "h46", theme: "histoire", question: "Quand et pourquoi la Troisième République est-elle proclamée ?", answer: "Le 4 septembre 1870, après la défaite de Napoléon III face à la Prusse lors de la bataille de Sedan (Guerre franco-prussienne)." },
  { id: "h47", theme: "histoire", question: "Quels sont les événements marquants du début de la Troisième République ?", answer: " La Commune de Paris (1871) : insurrection populaire réprimée dans le sang.  La consolidation républicaine (années 1870-1880) face aux monarchistes.  Lois Jules Ferry (1881-1882) instaurant l'école gratuite, laïque et obligatoire.  Séparation de l’Église et de l’État (1905)." },
  { id: "h48", theme: "histoire", question: "Comment la Troisième République prend-elle fin ?", answer: "Elle prend fin le 10 juillet 1940, lorsque le maréchal Pétain obtient les pleins pouvoirs et met en place l’État français (régime de Vichy)." },
  { id: "h49", theme: "histoire", question: "Qu'est-ce que le régime de Vichy et pourquoi a-t-il été instauré ?", answer: "Le régime de Vichy, officiellement \"l’État français\", est le gouvernement mis en place après la défaite de la France face à l'Allemagne nazie en juin 1940. Le 10 juillet 1940, l’Assemblée nationale vote les pleins pouvoirs au maréchal Philippe Pétain, mettant ainsi fin à la Troisième République." },
  { id: "h50", theme: "histoire", question: "Quand et comment prend fin le régime de Vichy ?", answer: " Le régime s’effondre avec la Libération de la France en 1944, menée par les Alliés et la Résistance.  6 juin 1944 : Débarquement en Normandie.  25 août 1944 : Libération de Paris.  Pétain fuit en Allemagne, puis en Suisse. Il est arrêté en 1945." },
  { id: "h51", theme: "histoire", question: "Quand la Quatrième République est-elle instaurée ?", answer: "Après la Seconde Guerre mondiale, la nouvelle Constitution est adoptée par référendum le 13 octobre 1946, rétablissant la République." },
  { id: "h52", theme: "histoire", question: "Quels sont les grands événements sous la Quatrième République ?", answer: " Reconstruction économique après la guerre.  Décolonisation : Indépendance de l’Indochine (1954) et début de la guerre d’Algérie (1954-1962).  Création de la Sécurité sociale (1945).  Droit de vote des femmes (1944, mais exercé pour la première fois en 1945)." },
  { id: "h53", theme: "histoire", question: "Quelles sont les dates de la Première et la seconde Guerre Mondiale ?", answer: " La Première Guerre Mondiale, un conflit mondial d'une ampleur sans précédent, s'est déroulée du 28 Juillet 1914 au 11 Novembre 1918, impliquant de nombreux pays et causant des pertes humaines et matérielles massives." },
  { id: "h54", theme: "histoire", question: "Quelle est la date exacte du début et de la fin de la Première Guerre mondiale ?", answer: "La guerre a commencé le 28 juillet 1914 avec la déclaration de guerre de l’Autriche-Hongrie à la Serbie et s’est terminée le 11 novembre 1918 avec l’armistice signé à Rethondes." },
  { id: "h55", theme: "histoire", question: "Quelles sont les causes principales de cette guerre ?", answer: " Tensions nationalistes en Europe.  Système d’alliances entre les grandes puissances.  L’attentat de Sarajevo (28 juin 1914), où l’archiduc François-Ferdinand d’Autriche a été assassiné." },
  { id: "h56", theme: "histoire", question: "Quels sont les principaux personnages de la Première Guerre mondiale ?", answer: " Georges Clemenceau : Président du Conseil français surnommé \"Le Tigre\".  Maréchal Foch : Commandant en chef des forces alliées.  Wilhelm II : Empereur d’Allemagne.  Lénine : Dirigeant de la révolution bolchévique en Russie (1917)." },
  { id: "h57", theme: "histoire", question: "Quels sont les traités mettant fin à la guerre ?", answer: " Traité de Versailles (28 juin 1919) : Imposant de lourdes sanctions à l’Allemagne.  Traité de Saint-Germain (1919) : Dissolution de l’Empire austro-hongrois." },
  { id: "h58", theme: "histoire", question: "Quelles sont les conséquences de la Première Guerre mondiale?", answer: " Environ 10 millions de morts.  Chute des Empires allemand, russe, austro-hongrois et ottoman.  Création de la Société des Nations (SDN)." },
  { id: "h59", theme: "histoire", question: "Quelles sont les principales batailles de la Première Guerre mondiale ?", answer: " Bataille de la Marne (6-12 septembre 1914) : Première grande bataille où les Français et les Britanniques stoppent l’avancée allemande vers Paris.  Bataille de Verdun (21 février - 18 décembre 1916) : Bataille d'usure entre la France et l’Allemagne, symbole de la résistance française." },
  { id: "h60", theme: "histoire", question: "Que commémore-t-on le 11 novembre en France ?", answer: "Le 11 novembre correspond à la signature de l'armistice mettant fin à la Première Guerre mondiale. Ce jour est férié en commémoration de la victoire de la France et de la paix" },
  { id: "h61", theme: "histoire", question: "Qu'est-ce qui s'est passé le 3 août 1914 ??", answer: "Le 3 août 1914, à 18 heures, l'Allemagne annonce son entrée en guerre contre la France." },
  { id: "h62", theme: "histoire", question: "Quels sont les principaux personnages de la Seconde Guerre mondiale ?", answer: " Charles de Gaulle : Chef de la France libre et futur président.  Jean Moulin : Héros de la Résistance française.  Winston Churchill : Premier ministre du Royaume-Uni.  Franklin D. Roosevelt : Président des États-Unis.  Joseph Staline : Dirigeant de l’URSS." },
  { id: "h63", theme: "histoire", question: "Quelles sont les batailles majeures de la Seconde Guerre mondiale ?", answer: " Bataille de France (mai-juin 1940) : Défaite française et occupation.  Bataille de Stalingrad (1942-1943) : Victoire soviétique contre l’Allemagne.  Débarquement de Normandie (6 juin 1944) : Libération de la France." },
  { id: "h64", theme: "histoire", question: "Qui était Jean Moulin ?", answer: "Jean Moulin était un haut fonctionnaire et résistant français pendant la Seconde Guerre mondiale. Il est connu pour avoir unifié les mouvements de la Résistance sous l’autorité de la France libre dirigée par Charles de Gaulle." },
  { id: "h65", theme: "histoire", question: "Quel était son rôle dans la Résistance ?", answer: "Jean Moulin a été chargé par Charles de Gaulle d’unifier les différents groupes de la Résistance en 1942. Il a créé le Conseil national de la Résistance (CNR) en 1943 pour coordonner les actions contre l’occupant allemand." },
  { id: "h66", theme: "histoire", question: "Comment Jean Moulin est-il mort ?", answer: "Il a été arrêté par la Gestapo le 21 juin 1943 à Caluire, près de Lyon, après une trahison. Torturé par Klaus Barbie, chef de la Gestapo à Lyon, il est mort des suites de ses blessures durant son transfert vers l'Allemagne, le 8 juillet 1943." },
  { id: "h67", theme: "histoire", question: "Pourquoi Jean Moulin est-il un symbole de la Résistance ?", answer: "Il incarne l’unité et le courage de la Résistance face à l’occupation nazie. Il a donné sa vie pour la libération de la France et repose depuis 1964 au Panthéon, un honneur réservé aux grandes figures de l’histoire nationale." },
  { id: "h68", theme: "histoire", question: "Pourquoi la Seconde Guerre mondiale s’est-elle terminée le 2 septembre 1945 et non le 8 mai 1945 ?", answer: "La Seconde Guerre mondiale s’est déroulée sur plusieurs continents et s’est terminée à des dates différentes selon les théâtres d’opération.  Le 8 mai 1945 marque la capitulation de l'Allemagne nazie face aux Alliés. C'est la fin de la guerre en Europe, appelée la Victoire en Europe (VE Day)." },
  { id: "h69", theme: "histoire", question: "Qu'est-ce que la Déclaration des Droits de l'Homme et du Citoyen ?", answer: "La Déclaration des Droits de l'Homme et du Citoyen, adoptée en 1789 pendant la Révolution Française, est un document fondamental qui établit les droits et libertés individuels. Elle est considérée comme une pierre angulaire des principes modernes de droits humains et de démocratie." },
  { id: "h70", theme: "histoire", question: "Qu'est-ce que le Traité de Versailles ?", answer: "Le Traité de Versailles, signé en 1919, a mis officiellement fin à la Première Guerre Mondiale. Ce traité a imposé de lourdes réparations et des restrictions territoriales à l'Allemagne, et a redessiné la carte de l'Europe. Cependant, il est aussi considéré comme ayant semé les graines du mécontentement menant à la Seconde Guerre Mondiale." },
  { id: "h71", theme: "histoire", question: "Quel était le but de la construction de la Tour Eiffel ?", answer: "La Tour Eiffel a été construite par Gustave Eiffel et ses collaborateurs pour l'Exposition universelle de 1889 à Paris. Initialement controversée, elle est aujourd'hui un symbole emblématique de Paris et de la France, reconnue dans le monde entier." },
  { id: "h72", theme: "histoire", question: "Quelle est l'importance de la bataille de Verdun durant la Première Guerre Mondiale ?", answer: "La bataille de Verdun, en 1916, est l'une des plus longues et des plus sanglantes de la Première Guerre Mondiale. Elle symbolise la résistance et la ténacité des forces françaises face à l'armée allemande et est devenue un symbole du sacrifice militaire français." },
  { id: "h73", theme: "histoire", question: "Qu'est-ce que le Front Populaire ?", answer: "Le Front Populaire, une coalition de partis de gauche, a été au pouvoir en France dans les années 1930. Il est célèbre pour avoir mis en œuvre des réformes sociales importantes, dont la semaine de travail de 40 heures et les congés payés." },
  { id: "h74", theme: "histoire", question: "Quel est le rôle de Napoléon Bonaparte dans l'histoire de France ?", answer: "Napoléon Bonaparte, général de la Révolution française, est devenu par la suite empereur des Français. Il a conduit la France à de nombreuses victoires militaires en Europe et a instauré des réformes importantes, dont le Code civil, qui a profondément influencé le système juridique français." },
  { id: "h75", theme: "histoire", question: "Qu'est-ce que la Convention nationale ?", answer: "La Convention nationale était l'assemblée qui gouvernait la France du 21 septembre 1792 au 26 octobre 1795, pendant la Première République. Elle a aboli la monarchie, proclamé la République et jugé Louis XVI (16)." },
  { id: "h76", theme: "histoire", question: "Qu'est-ce que la Chute de l'Empire Napoléonien ?", answer: "La chute de l'Empire Napoléonien a commencé avec la désastreuse campagne de Russie en 1812, suivie de défaites majeures. Napoléon a été finalement vaincu à la bataille de Waterloo en 1815, marquant la fin de son règne et un tournant majeur dans l'histoire européenne." },
  { id: "h77", theme: "histoire", question: "Quelle est l'importance de la Loi de séparation des Églises et de l'État de 1905 ?", answer: "La Loi de séparation des Églises et de l'État, adoptée en 1905, a établi la laïcité en France. Elle a mis fin au financement public des religions et a affirmé la neutralité de l'État en matière religieuse, jouant un rôle clé dans l'établissement de la liberté religieuse et de l'égalité de tous les citoyens devant la lo." },
  { id: "h78", theme: "histoire", question: "Comment la France a-t-elle été impliquée dans la colonisation ?", answer: "La France a été une des principales puissances coloniales, avec un empire s'étendant sur plusieurs continents, notamment en Afrique, en Asie et dans les Caraïbes. La colonisation a eu des répercussions durables sur ces régions et continue d'influencer les relations internationales et la politique française." },
  { id: "h79", theme: "histoire", question: "Quel a été le rôle de la France dans la création de l'Union européenne ?", answer: "La France a joué un rôle crucial dans la création de l'Union européenne, notamment à travers les efforts de Robert Schuman et Jean Monnet après la Seconde Guerre Mondiale. L'objectif était de créer une coopération économique et politique en Europe pour assurer la paix et la stabilité." },
  { id: "h80", theme: "histoire", question: "Qu'est-ce que les Lumières et quel a été leur impact sur la France ?", answer: "Le siècle des Lumières, au 18e siècle, a été une période de grands progrès intellectuels et philosophiques. En France, les philosophes des Lumières, tels que Voltaire et Rousseau, ont remis en question les traditions et proposé des idées sur la démocratie, l'égalité et la liberté, influençant fortement la Révolution Française et la pensée moderne." },
  { id: "h81", theme: "histoire", question: "Quand l’esclavage a-t-il été aboli en France ?", answer: "L’abolition de l’esclavage en France date du 27 avril 1848, sous l’impulsion de Victor Schœlcher.", date: "27 avril 1848", president: "Louis-Napoléon Bonaparte" },
  { id: "h82", theme: "histoire", question: "Quelle est l’importance de l’abolition de l’esclavage ?", answer: "L’abolition a marqué une avancée majeure pour les droits de l’Homme et la reconnaissance de l’égalité entre tous les citoyens." },
  { id: "h83", theme: "histoire", question: "Pourquoi l’abolition de l’esclavage en France a-t-elle plusieurs dates ? Quelle est la date définitive?", answer: "L’abolition de l’esclavage en France s’est faite en plusieurs étapes, ce qui explique la diversité des dates :  1794 (et non 1792) : Première abolition sous la Révolution française (par la Convention). Mais Napoléon Bonaparte la rétablit en 1802." },
  { id: "h84", theme: "histoire", question: "Quel est le contexte de la Déclaration de guerre de la France à la Prusse en 1870 ?", answer: "La déclaration de guerre de la France à la Prusse en 1870, qui a déclenché la Guerre francoprussienne, est survenue dans un contexte de tensions diplomatiques et de rivalités nationales. La défaite de la France a conduit à la chute du Second Empire et à la proclamation de la Troisième République." },
  { id: "h85", theme: "histoire", question: "Quelle est l'histoire derrière la construction du Château de Versailles ?", answer: "Le Château de Versailles, construit sous Louis XIV (14), est un symbole de la monarchie absolue de l'Ancien Régime. Il a servi de résidence royale et de centre du pouvoir jusqu'à la Révolution Française, et est reconnu pour son architecture et ses jardins somptueux." },
  { id: "h86", theme: "histoire", question: "Qui est Simone Veil ?", answer: "Simone Veil (1927-2017) était une femme politique française, rescapée de la déportation pendant la Seconde Guerre mondiale. Elle est principalement connue pour avoir porté la loi dépénalisant l’interruption volontaire de grossesse (IVG) en 1975 lorsqu’elle était ministre de la Santé.", date: "17 janvier 1975 (loi IVG)", president: "Valéry Giscard d’Estaing" },
  { id: "h87", theme: "histoire", question: "Comment s'est terminé le régime de Napoléon III ?", answer: "Le régime de Napoléon III, également connu sous le nom de Second Empire, s'est terminé après la défaite de la France dans la Guerre franco-prussienne en 1870. Sa capture à la bataille de Sedan a mené à sa déposition et à la proclamation de la Troisième République." },
  { id: "h88", theme: "histoire", question: "Combien y a-t-il eu de Napoléon et quelle est la différence entre eux ?", answer: "Il y a eu trois Napoléon qui ont régné en France : 1. Napoléon Ier (Napoléon Bonaparte) – 1804-1815  Premier empereur des Français (sacré en 1804).  Grand stratège militaire, il conquiert une grande partie de l’Europe.  Défait en 1814, revient au pouvoir en 1815 (les Cent-Jours) mais perd à Waterloo, ce qui marque sa chute définitive. 2." },
  { id: "h89", theme: "histoire", question: "Quel a été l'impact de la Conférence de Berlin de 1884-1885 sur la colonisation française ?", answer: "La Conférence de Berlin, à laquelle la France a participé, a été organisée pour réguler la colonisation et le commerce en Afrique. Elle a conduit à une augmentation de la présence coloniale française en Afrique, mais a aussi exacerbé les tensions coloniales et a eu des conséquences durables sur les populations africaines." },
  { id: "h90", theme: "histoire", question: "Quelle est l'importance du traité de Maastricht pour la France ?", answer: "Le traité de Maastricht, signé en 1992, a marqué une étape majeure dans l'intégration européenne. Pour la France, ce traité a signifié un engagement accru envers l'Union européenne, notamment à travers la création de l'Union économique et monétaire et l'introduction de l'euro.", date: "7 février 1992", president: "François Mitterrand" },
  { id: "h91", theme: "histoire", question: "Qu'est-ce que la Francophonie et quel est son rôle ?", answer: "La Francophonie est une organisation internationale regroupant des pays et régions où le français est une langue majeure. Pour la France, elle représente un moyen de promouvoir la langue française, ainsi que les valeurs culturelles, éducatives et politiques associées." },
  { id: "h92", theme: "histoire", question: "Quel a été l'impact de la Révolution industrielle en France ?", answer: "La Révolution industrielle, débutant au 19e siècle, a transformé l'économie française, passant d'une base agricole à une industrialisation croissante. Cela a entraîné des changements sociaux importants, y compris l'urbanisation et l'émergence de nouvelles classes sociales." },
  { id: "h93", theme: "histoire", question: "Qu'est-ce que le Mai 68 en France ?", answer: "Mai 68 désigne une période de vastes manifestations étudiantes et de grèves générales. Ce mouvement social a contesté les structures traditionnelles et autoritaires, menant à des réformes significatives dans l'éducation et le travail." },
  { id: "h94", theme: "histoire", question: "Quel a été le rôle de la France dans la fondation de l'ONU ?", answer: "La France est l'un des membres fondateurs de l'Organisation des Nations Unies (ONU) et l'un de ses cinq membres permanents du Conseil de sécurité. Son rôle dans la fondation de l'ONU reflète son engagement en faveur de la paix et de la coopération internationale après la Seconde Guerre Mondiale." },
  { id: "h95", theme: "histoire", question: "Qui était Louis XIV (14) et quelle est sa contribution à l'histoire de France ?", answer: "Louis XIV (14), surnommé le Roi-Soleil, a régné pendant plus de 72 ans. Il est connu pour son gouvernement absolutiste et la construction du Château de Versailles. Son règne a marqué l'apogée de la puissance française en Europe." },
  { id: "h96", theme: "histoire", question: "Quel a été le rôle de la France dans la guerre de Sécession américaine ?", answer: "Bien que la France soit restée officiellement neutre pendant la guerre de Sécession américaine, Napoléon III avait des sympathies pour la Confédération et avait envisagé de reconnaître son indépendance. Cependant, les succès de l'Union ont empêché toute intervention française." },
  { id: "h97", theme: "histoire", question: "Quelle a été l'importance du traité de Versailles pour la France après la Première Guerre Mondiale ?", answer: "Le traité de Versailles en 1919 a été crucial pour la France, qui cherchait à affaiblir l'Allemagne et à garantir sa propre sécurité. Le traité a imposé des réparations sévères à l'Allemagne et a redéfini les frontières européennes." },
  { id: "h98", theme: "histoire", question: "Quelle était la politique de la France envers l'Allemagne après la Seconde Guerre Mondiale ?", answer: "Après la Seconde Guerre Mondiale, la France, sous la direction de Charles de Gaulle et d'autres, a cherché à intégrer l'Allemagne dans un cadre européen coopératif, marquant un tournant dans les relations franco-allemandes et conduisant à la création de la Communauté européenne." },
  { id: "h99", theme: "histoire", question: "Qui étaient les Alliés pendant les deux guerres mondiales ?", answer: "Première Guerre mondiale : Les Alliés incluent la France, le Royaume-Uni, la Russie et, dès 1917, les États-Unis. Deuxième Guerre mondiale : Les Alliés regroupent la France, le Royaume-Uni, l’URSS et les États-Unis." },
  { id: "h100", theme: "histoire", question: "Quels sont les moments clés de la Cinquième République ?", answer: " 1962 : Référendum instaurant l’élection du président au suffrage universel direct.  1968 : Crise étudiante et sociale de Mai 68.  1974 : Majorité abaissée à 18 ans.  1981 : Abolition de la peine de mort sous François Mitterrand.  1992 : Traité de Maastricht, création de l’Union européenne." },
  { id: "h101", theme: "histoire", question: "Qu’est-ce qui change avec la Cinquième République ?", answer: "La Cinquième République se distingue notamment par :  Le président est élu au suffrage universel direct (depuis 1962).  Le président a le pouvoir de nommer le Premier ministre, dissoudre l’Assemblée nationale et recourir à des pouvoirs exceptionnels (article 16)." },
  { id: "h102", theme: "histoire", question: "Qui était Maximilien Robespierre et quel était son rôle pendant la Révolution ?", answer: "Maximilien Robespierre était un leader influent pendant la Révolution française, notamment pendant la période de la Terreur. Il était membre du Comité de salut public et a joué un rôle clé dans la lutte contre les ennemis de la Révolution, mais sa gouvernance stricte et ses politiques radicales ont conduit à sa chute et à son exécution." },
  { id: "h103", theme: "histoire", question: "Qu'est-ce que la Terreur, et pourquoi est-elle importante dans le contexte de la Révolution française ?", answer: "La Terreur (1793-1794) était une période de la Révolution française caractérisée par des arrestations massives, des procès rapides et des exécutions, souvent par guillotine." },
  { id: "h104", theme: "histoire", question: "Quelle était la signification de la guillotine pendant la Révolution française ?", answer: "La guillotine, souvent associée à la Terreur, était vue comme un moyen d'exécution plus humanitaire et égalitaire. Elle est devenue un symbole puissant de la Révolution, utilisée pour exécuter des milliers de personnes, y compris le roi Louis XVI (16) et Robespierre." },
  { id: "h105", theme: "histoire", question: "Quelles étaient les causes de la chute de la monarchie française pendant la Révolution ?", answer: "La chute de la monarchie en 1792 peut être attribuée à une combinaison de facteurs, notamment l'insatisfaction populaire face à la crise économique, les idées révolutionnaires de liberté et d'égalité, et l'incapacité du roi à répondre efficacement aux demandes du peuple et à gérer la crise." },
  { id: "h106", theme: "histoire", question: "Comment la Révolution française a-t- elle influencé les autres pays européens ?", answer: "La Révolution française a eu un impact profond en Europe, inspirant des mouvements révolutionnaires et des réformes démocratiques dans d'autres pays. Elle a également mené à une série de guerres révolutionnaires entre la France et diverses coalitions européennes." },
  { id: "h107", theme: "histoire", question: "Quelles étaient les conséquences de la Révolution française pour la société française ?", answer: "La Révolution a radicalement transformé la société française, abolissant la monarchie et l'ordre féodal, instaurant une république, et promouvant des idéaux de liberté, d'égalité et de laïcité. Elle a également conduit à des changements sociaux et économiques majeurs et à la redéfinition de la structure politique et sociale de la France." },
  { id: "h108", theme: "histoire", question: "Pouvez-vous citer quelques rois de France ?", answer: "Quelques rois de France célèbres sont Louis XIV (14), Louis XVI (16), Louis XV (15), François Ier, et Henri IV (4)." },
  { id: "h109", theme: "histoire", question: "Pouvez-vous nommer quelques reines de France ?", answer: "Parmi les reines de France, on peut citer Marie-Antoinette, Catherine de Médicis, et Marie de Médicis, Anne de Bretagne, Aliénor d’Aquitaine." },
  { id: "h110", theme: "histoire", question: "Qui était l'épouse de Louis XVI (16) ?", answer: "Marie-Antoinette était l'épouse de Louis XVI (16)." },
  { id: "h111", theme: "histoire", question: "Question: Qu'est-ce que la Fronde ?", answer: "Une série de révoltes contre le pouvoir royal au XVI (16) éme siècle." },
  { id: "h112", theme: "histoire", question: "Qui était Jeanne d'Arc ?", answer: "Jeanne d'Arc (1412–1431) est une héroïne nationale française, symbole de courage et de patriotisme. Paysanne lorraine guidée par des voix, elle a conduit les troupes françaises à libérer Orléans pendant la guerre de Cent Ans, permettant le sacre du roi Charles VII à Reims en 1429. Capturée par les Bourguignons, elle fut livrée aux Anglais et brûlée vive à Rouen en 1431. Elle est aujourd'hui sainte de l'Église catholique et symbole de la résistance française." },
  { id: "h113", theme: "histoire", question: "Quand les femmes ont-elles obtenu le droit de vote en France ?", answer: "Les femmes ont obtenu le droit de vote par ordonnance du général de Gaulle le 21 avril 1944, pendant la Libération. Elles l'ont exercé pour la première fois lors des élections municipales d'avril 1945. La France a été l'un des derniers grands pays démocratiques à accorder ce droit aux femmes." },
  { id: "h114", theme: "histoire", question: "Que représente le 1er mai en France ?", answer: "Le 1er mai est la fête du Travail, jour férié en France depuis 1947. Il commémore les luttes ouvrières pour les droits des travailleurs, notamment la revendication des 8 heures de travail par jour. C'est un jour de défilés syndicaux et de solidarité, symbolisé par le brin de muguet offert pour porter bonheur." },
  { id: "h115", theme: "histoire", question: "Comment était le pouvoir en France avant la Révolution française ?", answer: "Avant la Révolution française, la France était gouvernée par une monarchie absolue. Le roi détenait tous les pouvoirs — exécutif, législatif et judiciaire — sans avoir à rendre de comptes à personne. Louis XVI était le roi en 1789. Le peuple, accablé par les impôts et la famine, n'avait aucun droit politique. La Révolution a mis fin à cet absolutisme et posé les bases de la République." },

  // ─── INSTITUTIONS───────────────────────────────────────────────────────────────
  { id: "i01", theme: "institutions", question: "Qu’est-ce qu’un Français ?", answer: "Un Français est une personne qui appartient à la nation française par sa culture, son histoire, sa langue et son attachement aux valeurs républicaines." },
  { id: "i02", theme: "institutions", question: "Qu’est-ce qu’un citoyen français ?", answer: "Un citoyen français est une personne qui participe activement à la vie de la nation. Il ne se contente pas d’appartenir à la France, il contribue à son avenir par ses actions, ses choix et son engagement." },
  { id: "i03", theme: "institutions", question: "Qu’est-ce que le Brexit ?", answer: "Le Brexit désigne la sortie du Royaume-Uni de l’Union européenne, décidée par référendum en 2016 et effective depuis le 31 janvier 2020." },
  { id: "i04", theme: "institutions", question: "Quelles ont été les conséquences du Brexit ?", answer: "Le Brexit a eu des impacts économiques, politiques et administratifs sur les échanges entre le Royaume-Uni et l’Union européenne." },
  { id: "i05", theme: "institutions", question: "Pouvez-vous citer quelques partis politiques français ?", answer: "Parmi les principaux partis politiques en France, on trouve Renaissance (ex-La République en Marche), Les Républicains, le Parti Socialiste, La France Insoumise et le Rassemblement National." },
  { id: "i06", theme: "institutions", question: "Les femmes peuvent-elles s’habiller comme elles le souhaitent en France ?", answer: "Oui, en France, la loi garantit la liberté vestimentaire, dans le respect de l’ordre public." },
  { id: "i07", theme: "institutions", question: "Quelles sont les idées qu’on ne doit pas exprimer ?", answer: "En France, la liberté d’expression est garantie, mais elle est encadrée par la loi. Il est interdit par exemple d’inciter à la haine, à la violence ou de tenir des propos discriminatoires." },
  { id: "i08", theme: "institutions", question: "Pourquoi la France a-t-elle organisé des élections législatives anticipées en 2024 ?", answer: "La dissolution de l'Assemblée nationale par le président Emmanuel Macron a entraîné des élections anticipées en raison d'une impasse législative suite aux élections européennes qui ont eu lieu en juin 2024." },
  { id: "i09", theme: "institutions", question: "Les élections ont-elles permis de former une majorité au Parlement ?", answer: "Non, aucun groupe politique n’a obtenu de majorité absolue, ce qui a laissé l'Assemblée nationale fragmentée. Les partis doivent donc négocier des accords pour former une majorité de gouvernance, faute de quoi de nouvelles élections pourraient être envisagées." },
  { id: "i10", theme: "valeurs", question: "La signification de la Fraternité ?", answer: "La France est construite sur le désir de cohabitation harmonieuse entre ses citoyens, exprimant ainsi la solidarité entre eux." },
  { id: "i11", theme: "institutions", question: "Si l'on devait ajouter une cinquième valeur aux principes fondamentaux de la République française, que serait-elle selon vous ?", answer: "L'indivisibilité : signifie que la République ne peut être fragmentée : il n’existe qu’un seul peuple français, avec les mêmes lois sur tout le territoire." },
  { id: "i12", theme: "institutions", question: "Quel est le sens des couleurs du drapeau français ?", answer: "Le drapeau est composé de 3 couleurs sous formes de bandes verticales." },
  { id: "i13", theme: "valeurs", question: "Que représente Le coq ?", answer: "Le coq est un symbole national français. Il est souvent représenté sur les monuments, les édifices publics et les maillots des équipes sportives françaises. Le coq représente la fierté nationale, le courage et la vigilance." },
  { id: "i14", theme: "institutions", question: "Que signifie Le faisceau de licteur ?", answer: "Le faisceau de licteur est un symbole de l'autorité de l'État en France. Il représente l'unité et la force collective du peuple français. Il est composé d'un faisceau de verges entourant une hache, rappelant l'autorité de la République et la puissance de l'État." },
  { id: "i15", theme: "institutions", question: "Que signifie Le sceau de la république ?", answer: "Le sceau de la République française est utilisé pour authentifier les actes officiels du gouvernement. Il représente l'État et est généralement gravé sur les documents officiels et les pièces de monnaie. Le sceau peut varier dans sa représentation, mais il symbolise l'autorité et l'authenticité des décisions et des actes de l'État." },
  { id: "i16", theme: "institutions", question: "Que signifie la république pour vous ?", answer: "La république est un mode d'organisation d'un pays dans lequel le pouvoir est exercé par des représentants élus de la population (directement ou indirectement). Le chef de l'État exerçant un mandat temporaire est désigné pour un mandat limité (souvent par élection) et ne détient pas le pouvoir de manière exclusive." },
  { id: "i17", theme: "institutions", question: "Qu’est-ce qu’une Monarchie ?", answer: "La monarchie est un régime politique où le chef de l’État, appelé roi ou reine, hérite du pouvoir de manière héréditaire et l’exerce souvent à vie." },
  { id: "i18", theme: "institutions", question: "Qu'est-ce que la démocratie ?", answer: "La démocratie est une forme de gouvernement dans laquelle la souveraineté appartient au peuple. En d'autres termes, c'est un système de gouvernement du peuple, par le peuple et pour le peuple." },
  { id: "i19", theme: "institutions", question: "En quelle année la France est devenue démocratique ?", answer: "La France est devenue démocratique tels qu’elle est connue à nos jour, le 4 octobre 1958" },
  { id: "i20", theme: "institutions", question: "Quelle est la différence entre République et démocratie ?", answer: "Une république n'a pas de roi, mais cela ne signifie pas que c’est une démocratie, tandis qu'une démocratie signifie que le peuple a le pouvoir, et cela peut exister dans une république ou une monarchie.  Une république n’est pas forcément une démocratie. Ex : La Chine est une république mais pas une démocratie (régime autoritaire)." },
  { id: "i21", theme: "institutions", question: "Quels sont les différents types de Monarchies ?", answer: " Monarchie absolue → Le roi détient tous les pouvoirs (ex : Arabie Saoudite).  Monarchie constitutionnelle → Le roi règne mais ne gouverne pas, il partage le pouvoir avec un gouvernement élu (ex : Royaume-Uni, Espagne).  Monarchie parlementaire → Le roi a un rôle symbolique, tout le pouvoir appartient au parlement élu (ex : Suède, Belgique)." },
  { id: "i22", theme: "institutions", question: "Quels sont les différents types de Républiques ?", answer: " République présidentielle → Le président a beaucoup de pouvoirs, il est à la fois chef de l’État et chef du gouvernement (ex : États-Unis, Brésil).  République parlementaire → Le pouvoir est surtout entre les mains du parlement et du Premier ministre, le président a un rôle limité (ex : Allemagne, Italie)." },
  { id: "i23", theme: "institutions", question: "Qui occupe actuellement la fonction de président de la République ?", answer: "Le président de la République actuel est Emmanuel Macron. Il est le huitième président de la Cinquième République." },
  { id: "i24", theme: "institutions", question: "Où se situe le siège de la Présidence de la République ?", answer: "Le siège de la Présidence de la République est situé à l'Élysée." },
  { id: "i25", theme: "institutions", question: "Quelle est la durée du mandat présidentiel?", answer: "Le président de la République est élu pour un mandat de 5 ans" },
  { id: "i26", theme: "institutions", question: "Dans quelle république nous trouvons-nous actuellement ?", answer: "Nous nous trouvons actuellement dans la Cinquième République, instaurée par Charles de Gaulle." },
  { id: "i27", theme: "institutions", question: "Quand la Cinquième République a-t-elle été instaurée et quel événement marquant l'a accompagnée ?", answer: "La Constitution de la Cinquième République a été adoptée le 4 octobre 1958, marquant ainsi la séparation des pouvoirs exécutif, législatif et judiciaire.", date: "4 octobre 1958", president: "Charles de Gaulle" },
  { id: "i28", theme: "institutions", question: "Pouvez-vous citer les présidents de la Cinquième République dans l’ordre ?", answer: "Les présidents de la Cinquième République sont :  Charles De Gaulle : 1959 - 1969  Georges Pompidou : 1969- 1974  Valéry Giscard d'Estaing : 1974-1981  François Mitterrand : 1981-1995  Jacques Chirac : 1995-2007  Nicolas Sarkozy : 2007-2012  François Hollande : 2012 - 2017  Emmanuel Macron : 2017- Mandat en cours" },
  { id: "i29", theme: "institutions", question: "Qui détient le commandement de l'armée ?", answer: "Le président de la République." },
  { id: "i30", theme: "institutions", question: "Comment le président gouverne-t-il le pays ?", answer: "Le président gouverne en dirigeant l'exécutif, en prenant des décisions politiques, en promulguant des lois, et en représentant le pays à l'international." },
  { id: "i31", theme: "institutions", question: "Quelles sont les 3 types de collectivités en France ?", answer: "Communes Nombre : Environ 35 000. Rôle : Les communes constituent le niveau administratif le plus local. Elles sont responsables de nombreux services de proximité, tels que l'entretien des écoles primaires, l'urbanisme local, l'organisation des services de secours, et la collecte des ordures ménagères." },
  { id: "i32", theme: "institutions", question: "Quel est le système politique de la France ?", answer: "Une république semi-présidentielle." },
  { id: "i33", theme: "institutions", question: "Quel est le régime politique de la France ?", answer: "La France est une république démocratique." },
  { id: "i34", theme: "institutions", question: "Qui est le premier ministre actuel ?", answer: "Sébastien Lecornu, nommé Premier ministre en octobre 2025 par le président Emmanuel Macron." },
  { id: "i35", theme: "institutions", question: "Quel est le rôle du Premier ministre en France ?", answer: "Diriger le gouvernement et mettre en œuvre la politique nationale." },
  { id: "i36", theme: "institutions", question: "Où se trouve le siège du Premier ministre ?", answer: "À l’Hôtel de Matignon, à Paris." },
  { id: "i37", theme: "institutions", question: "Quels types d’élections ont lieu en France ?", answer: "En France, on trouve les élections présidentielles (5ans), législatives (5ans), municipales (6ans), régionales (6ans), européennes (5ans), et les élections départementales (6ans)." },
  { id: "i38", theme: "institutions", question: "Quelles sont les prochaines élections ?", answer: "Les prochaines élections en France sont les suivantes :  Élections municipales : Prévu en mars 2026, ces élections permettront de désigner les maires et les conseils municipaux des communes.  Élections sénatoriales : Elles auront lieu en 2027, pour renouveler une partie du Sénat." },
  { id: "i39", theme: "institutions", question: "Quelles sont les principales institutions de la République française ?", answer: "Les institutions comprennent :  Le pouvoir exécutif : Ce pouvoir est détenu par le président de la République et le gouvernement dirigé par le Premier ministre. Ils sont responsables de l’application des lois et de la gestion de la politique nationale et internationale." },
  { id: "i40", theme: "institutions", question: "C’est quoi le gouvernement ?", answer: "Le gouvernement est l'organe exécutif chargé de mettre en œuvre les lois et de gérer le pays. Il est dirigé par le Premier ministre et comprend des ministres, chacun responsable d'un secteur particulier comme l'économie ou la santé. Les secrétaires d'État sont des membres du gouvernement qui assistent les ministres dans des domaines spécifiques." },
  { id: "i41", theme: "institutions", question: "De quoi est composé le parlement français ?", answer: "Le parlement français est composé de deux chambres (bicaméral), c'est-à-dire:  Le Sénat, appelée « chambre haute », avec 348 sénateurs,  L’Assemblée nationale, dite « chambre basse », avec 577 députés." },
  { id: "i42", theme: "institutions", question: "Qu'est-ce que le Sénat en France ?", answer: "Le Sénat est la chambre haute du Parlement français. Il est composé de 348 sénateurs élus au suffrage universel indirect pour un mandat de 6 ans. Le Sénat participe à l'élaboration des lois, les examine et peut les amender, mais il ne peut pas empêcher leur adoption." },
  { id: "i43", theme: "institutions", question: "Qu'est-ce que l'Assemblée nationale ?", answer: "L'Assemblée nationale est la chambre basse du Parlement français. Elle est composée de 577 députés élus par les citoyens au suffrage universel direct pour un mandat de 5 ans. L'Assemblée nationale vote les lois et contrôle le gouvernement." },
  { id: "i44", theme: "institutions", question: "En cas de désaccord entre le sénat et l’assemble, qui a le dernier mot ?", answer: "L’Assemblée nationale a le dernier mot en cas de désaccord entre les deux chambres (AN et Sénat). Si l'Assemblée nationale adopte un texte de loi après un désaccord avec le Sénat, elle peut décider de l'adopter définitivement sans l'accord du Sénat. Toutefois, le Sénat peut proposer des modifications et renvoyer le texte à l'Assemblée nationale." },
  { id: "i45", theme: "institutions", question: "Où siège le Conseil d’État?", answer: "Au Palais-Royal, à Paris." },
  { id: "i46", theme: "institutions", question: "Comment est élu le président du Sénat ?", answer: "Il est élu au scrutin secret par les sénateurs lors de chaque renouvellement partiel du Sénat, tous les 3 ans." },
  { id: "i47", theme: "institutions", question: "Qui peut être candidat à la présidence du Sénat ?", answer: "Tout sénateur peut se présenter." },
  { id: "i48", theme: "institutions", question: "Quelle est la durée du mandat du président du Sénat?", answer: "3 ans, renouvelable." },
  { id: "i49", theme: "institutions", question: "Pourquoi le président du Sénat est-il élu tous les 3 ans ?", answer: "Parce que le Sénat est renouvelé par moitié tous les 3 ans, et à chaque renouvellement, les sénateurs élisent un président." },
  { id: "i50", theme: "institutions", question: "Pourquoi parle-t-on de \"renouvellement partiel\" du Sénat ?", answer: "Contrairement à l’Assemblée nationale, qui est renouvelée entièrement tous les 5 ans, le Sénat est renouvelé par moitié tous les 3 ans pour assurer une certaine stabilité institutionnelle." },
  { id: "i51", theme: "institutions", question: "Quel est le rôle du président du Sénat ?", answer: "Il dirige les débats, assure le bon fonctionnement du Sénat et remplace le président de la République en cas de vacance du pouvoir." },
  { id: "i52", theme: "institutions", question: "Qui est le président l’assemblée nationale actuel ?", answer: "Yaël Braun-Pivet élue le Jeudi 18 juillet 2024." },
  { id: "i53", theme: "institutions", question: "Comment est élu le président de l’Assemblée nationale ?", answer: "Il est élu à la majorité absolue par les députés lors de la première séance de la législature, après les élections législatives." },
  { id: "i54", theme: "institutions", question: "Quelle est la durée du mandat du président de l’Assemblée nationale ?", answer: "5 ans, soit la durée de la législature." },
  { id: "i55", theme: "institutions", question: "Quel est le rôle du président de l’Assemblée nationale ?", answer: "Il dirige les débats, veille au respect du règlement et représente l’Assemblée nationale." },
  { id: "i56", theme: "institutions", question: "Quelle est la principale différence entre le Sénat et l'Assemblée nationale ?", answer: "L'Assemblée nationale est élue par le peuple, tandis que le Sénat est élu par un collège électoral." },
  { id: "i57", theme: "institutions", question: "Pourquoi le président de l’Assemblée nationale est-il élu pour 5 ans ?", answer: "Parce que l’Assemblée nationale est entièrement renouvelée à chaque élection législative, qui a lieu tous les 5 ans." },
  { id: "i58", theme: "institutions", question: "Pourquoi l’Assemblée nationale est-elle renouvelée entièrement et pas partiellement comme le Sénat ?", answer: "Car elle représente directement les citoyens, élus au suffrage universel direct. Un renouvellement total assure une représentation fidèle des choix électoraux." },
  { id: "i59", theme: "institutions", question: "Quel est le rôle du Parlement français ?", answer: "Il vote les lois et contrôle le gouvernement." },
  { id: "i60", theme: "institutions", question: "Le président de la République peut-il dissoudre le Sénat ?", answer: "Non, la Constitution ne lui donne pas ce pouvoir." },
  { id: "i61", theme: "institutions", question: "Le président de la République peut-il dissoudre l’Assemblée nationale ?", answer: "Oui, selon l’article 12 de la Constitution, il peut dissoudre l’Assemblée nationale à tout moment, après consultation du Premier ministre et des présidents des deux assemblées." },
  { id: "i62", theme: "institutions", question: "Pourquoi peut-il dissoudre l’Assemblée nationale ?", answer: "Parce que l’Assemblée nationale est élue au suffrage universel direct, elle représente directement le peuple. Sa dissolution permet de redonner la parole aux citoyens en cas de crise politique." },
  { id: "i63", theme: "institutions", question: "Pourquoi ne peut-il pas dissoudre le Sénat ?", answer: "Parce que le Sénat est élu au suffrage indirect par un collège de grands électeurs. Il incarne une stabilité institutionnelle, et sa dissolution pourrait fragiliser l’équilibre des pouvoirs." },
  { id: "i64", theme: "institutions", question: "C'est quoi l'article 49.3 ?", answer: "L'article 49.3 de la constitution permet au gouvernement de faire passer une loi sans vote à l’Assemblée nationale. Les députés peuvent répondre en déposant une motion de censure. Si elle est votée, le gouvernement tombe. Sinon, la loi est adoptée automatiquement." },
  { id: "i65", theme: "institutions", question: "C'est quoi une motion de censure ?", answer: "Une motion de censure est un vote organisé par l’Assemblée nationale pour exprimer un désaccord avec le gouvernement. Si la majorité des députés vote cette motion, le gouvernement doit démissionner." },
  { id: "i66", theme: "institutions", question: "Le Sénat peut-il déposer une motion de censure ?", answer: "Non, le Sénat ne peut pas déposer de motion de censure contre le gouvernement. Seule l’Assemblée nationale détient ce pouvoir, car elle représente directement les citoyens par le suffrage universel direct." },
  { id: "i67", theme: "institutions", question: "Quelles sont les conditions pour adopter une motion de censure ?", answer: "Pour qu'une motion de censure soit adoptée à l’Assemblée nationale, elle doit respecter plusieurs conditions notamment :  Être déposée par au moins 1/10ᵉ des députés (soit 58 sur 577).  Être votée à la majorité absolue des députés, soit au moins 289 voix sur 577. Si elle est adoptée, le gouvernement doit démissionner immédiatement." },
  { id: "i68", theme: "institutions", question: "Quel est le délai pour déposer une motion de censure après l’utilisation du 49.3 ?", answer: "Après l’engagement de la responsabilité du gouvernement sur un texte avec l’article 49.3, les députés ont un délai de 24 heures pour déposer une motion de censure. Passé ce délai, aucune motion ne peut être enregistrée, et la loi est adoptée automatiquement si aucune motion n’a été votée." },
  { id: "i69", theme: "institutions", question: "Le président de la République représente quel pouvoir ?", answer: "Il représente le pouvoir exécutif et est le garant des institutions, du respect de la Constitution et de l’indépendance nationale. Il nomme le Premier ministre et veille au bon fonctionnement des pouvoirs publics." },
  { id: "i70", theme: "institutions", question: "Qui détient le pouvoir exécutif et par qui est-il dirigé ?", answer: "Le pouvoir exécutif est détenu par le président de la République et le gouvernement, dirigé par le Premier ministre. Le gouvernement met en œuvre les décisions politiques sous l’autorité du président." },
  { id: "i71", theme: "institutions", question: "Qu'est-ce que la cohabitation en politique française ?", answer: "Une période où le Président de la République et le Premier ministre appartiennent à des camps politiques opposés." },
  { id: "i72", theme: "institutions", question: "Peut-on avoir une double nationalité en France ?", answer: "Oui, selon les accords entre pays." },
  { id: "i73", theme: "institutions", question: "Comment est élu le maire ?", answer: "Le maire est élu au suffrage indirect. Cela signifie que ce ne sont pas directement les habitants qui votent pour lui, mais les membres du conseil municipal." },
  { id: "i74", theme: "institutions", question: "Comment est élu le conseil municipal ?", answer: " Lors des élections municipales, les habitants de la commune votent pour élire les conseillers municipaux. Ces élections ont lieu tous les 6 ans.  Le mode de scrutin dépend de la taille de la commune (majoritaire pour les petites communes, proportionnel pour les grandes)." },
  { id: "i75", theme: "institutions", question: "Comment sont élus les adjoints aux maires :", answer: "Les adjoints au maire sont élus par le conseil municipal lors de sa première réunion après les élections municipales. L’élection se fait au scrutin de liste à la majorité absolue. Leur nombre est déterminé en fonction de la taille de la commune, et ils assistent le maire dans ses fonctions en recevant des délégations de compétences." },
  { id: "i76", theme: "institutions", question: "Comment sont élus les conseillers départementaux ?", answer: "Les conseillers départementaux sont élus pour six ans au suffrage universel direct, mais avec un scrutin binominal majoritaire à deux tours." },
  { id: "i77", theme: "institutions", question: "Comment sont élus les conseillers régionaux ?", answer: "Les conseillers régionaux sont élus pour six ans au suffrage universel direct lors des élections régionales. Le scrutin majoritaire est un vote de liste à deux tours." },
  { id: "i78", theme: "institutions", question: "Quelle est la différence entre un décret et une loi en France ?", answer: "Une loi est votée par le Parlement, tandis qu'un décret est un acte administratif pris par le Président ou le Premier ministre." },
  { id: "i79", theme: "institutions", question: "Qu'est-ce que l'ENA ?", answer: "L'École Nationale d'Administration, une grande école formant les hauts fonctionnaires." },
  { id: "i80", theme: "institutions", question: "Quelle est la population de la France ?", answer: "En 2024, la population française est estimée à environ 68 millions d’habitants." },
  { id: "i81", theme: "institutions", question: "Qui est le nouveau président du conseil constitutionnel?", answer: "Richard Ferrand nommé le 19 février 2025." },
  { id: "i82", theme: "institutions", question: "Comment est nommé le président du Conseil constitutionnel ?", answer: "Le président du Conseil constitutionnel est désigné par le président de la République parmi les membres du Conseil. Sa nomination doit être validée par les commissions des lois de l'Assemblée nationale et du Sénat." },
  { id: "i83", theme: "institutions", question: "Quel est le principe du service public en France ?", answer: "Assurer des services essentiels à tous les citoyens, indépendamment de la rentabilité." },
  { id: "i84", theme: "institutions", question: "Quelle est la différence entre la justice civile et la justice pénale en France ?", answer: "La justice civile règle les litiges entre personnes, tandis que la justice pénale s'occupe des infractions à la loi." },
  { id: "i85", theme: "institutions", question: "Quelle loi française interdit le port de signes ou de tenues manifestant ostensiblement une appartenance religieuse dans les écoles publiques ?", answer: "La loi du 15 mars 2004 interdit le port de signes religieux ostensibles dans les établissements scolaires publics.", date: "15 mars 2004", president: "Jacques Chirac" },
  { id: "i86", theme: "institutions", question: "Quelle est la nouvelle appellation de l’ENA depuis 2021 ?", answer: "L'École Nationale d'Administration, devenue l'Institut national du service public (INSP)." },
  { id: "i87", theme: "institutions", question: "Quelle est la fonction du Médiateur de la République ?", answer: "Aider à résoudre les litiges entre les citoyens et l'administration." },
  { id: "i88", theme: "institutions", question: "Combien y a-t-il eu de présidents sous la Cinquième République ?", answer: "Huit (8) présidents élus depuis 1958." },
  { id: "i89", theme: "institutions", question: "Quel animal représente la France ?", answer: "Le coq gaulois est un symbole emblématique de la France, souvent utilisé lors d'événements sportifs. Il incarne la fierté, la bravoure et l'esprit combatif des Français. Il est fréquemment visible sur les maillots des équipes nationales, notamment lors des compétitions internationales telles que la Coupe du Monde ou les Jeux Olympiques." },
  { id: "i90", theme: "institutions", question: "Quelle loi française interdit de fumer dans les lieux publics fermés ?", answer: "La loi Évin, en vigueur depuis 2007." },
  { id: "i91", theme: "institutions", question: "Quels sont les quatre premières personnalités de l'État en France ?", answer: " Le Président de la République → Chef de l'État, garant des institutions et de la Constitution.  Le Premier ministre → Chef du gouvernement, responsable de la politique nationale.  Le Président du Sénat → Deuxième personnage de l’État, il assure l’intérim en cas de vacance de la présidence." },
  { id: "i92", theme: "institutions", question: "De quoi étaient composés les états généraux ?", answer: "Les États généraux réunissaient les trois ordres de la société :  Le Clergé  La Noblesse  Le Tiers-État (98 % de la population)" },
  { id: "i93", theme: "institutions", question: "Comment la Terreur a-t-elle pris fin ?", answer: "Le 27 juillet 1794 (9 thermidor an II), Robespierre et ses partisans sont arrêtés et exécutés." },
  { id: "i94", theme: "institutions", question: "Comment fonctionne la Quatrième République ?", answer: "Un régime parlementaire, où le président de la République a peu de pouvoirs. Un gouvernement responsable devant l'Assemblée nationale, qui peut le renverser par une motion de censure." },
  { id: "i95", theme: "institutions", question: "Pourquoi la Quatrième République prend-elle fin ?", answer: "L’instabilité politique (plus de 20 gouvernements en 12 ans) et la crise de la guerre d’Algérie mènent au retour du général de Gaulle, qui propose une nouvelle Constitution en 1958, donnant naissance à la Cinquième République." },
  { id: "i96", theme: "institutions", question: "Quels sont les principaux traités mettant fin au conflit ?", answer: " Conférence de Yalta (février 1945) : Définition du partage de l’Europe après-guerre.  Traité de San Francisco (1951) : Paix entre le Japon et les Alliés." },
  { id: "i97", theme: "institutions", question: "Quelles sont les conséquences de la guerre ?", answer: " Environ 60 millions de morts.  Création de l’ONU (1945) pour garantir la paix.  Début de la Guerre froide entre États-Unis et URSS." },
  { id: "i98", theme: "institutions", question: "Qu'est-ce que le Panthéon à Paris ?", answer: "Le Panthéon est un monument à Paris, situé dans le Quartier Latin. Il est à la fois un lieu de sépulture et un symbole national où reposent de nombreuses personnalités françaises importantes." },
  { id: "i99", theme: "institutions", question: "Quel monument est offert par la France aux États-Unis pour célébrer le centenaire de leur indépendance ?", answer: "La Statue de la Liberté." },
  { id: "i100", theme: "institutions", question: "Qu'est-ce que le Groupe des Sept ou G7 ?", answer: "Un groupe de pays industrialisés dont la France fait partie, se réunissant annuellement pour discuter de questions économiques mondiales." },
  { id: "i101", theme: "institutions", question: "Quels pays ne font pas partie de l'Union européenne mais font partie de l'espace Schengen ?", answer: "Certains pays ne font pas partie de l'Union européenne mais font partie de l'Espace Schengen, qui permet la libre circulation des personnes entre ses membres." },
  { id: "i102", theme: "institutions", question: "Qui a composé l'hymne européen ?", answer: "Ludwig van Beethoven, L'Ode à la joie de sa 9ème symphonie." },
  { id: "i103", theme: "institutions", question: "En quelle année la France est-elle devenue membre de l'Union Européenne ?", answer: "1957, avec la signature du Traité de Rome (la France est l'un des membres fondateurs)." },
  { id: "i104", theme: "institutions", question: "Qu'est-ce que l'Union européenne (UE) ?", answer: "L'UE est une organisation politique et économique regroupant 27 pays européens. L'Eurovision est un concours de chansons annuel organisé par l'Union européenne de radio-télévision (UER). Bien qu'il ne soit pas directement lié à l'UE, plusieurs pays européens et quelques pays voisins y participent, mettant en avant la culture musicale européenne." },
  { id: "i105", theme: "institutions", question: "Quel est le drapeau de l'Union européenne ?", answer: "Le drapeau de l'UE est bleu avec 12 étoiles d'or en cercle." },
  { id: "i106", theme: "institutions", question: "Quelle est la monnaie utilisée dans la zone euro ?", answer: "La monnaie utilisée dans la zone euro est l'euro (€)." },
  { id: "i107", theme: "institutions", question: "Quels pays européens ne font pas partie de l'UE ?", answer: "Parmi les pays européens qui ne font pas partie de l'UE, on trouve la Norvège, la Suisse, et le RoyaumeUni." },
  { id: "i108", theme: "institutions", question: "Quelle est la capitale de l'Union européenne ?", answer: "La capitale de l'UE est Bruxelles, en Belgique." },
  { id: "i109", theme: "institutions", question: "Qu'est-ce que l'eurozone ?", answer: "L'eurozone est un groupe de pays de l'UE qui ont adopté l'euro comme monnaie commune." },
  { id: "i110", theme: "institutions", question: "Quels sont les objectifs principaux de l'UE ?", answer: "Les principaux objectifs de l'UE sont la paix, la stabilité, la prospérité économique, et la coopération entre les pays membres." },
  { id: "i111", theme: "institutions", question: "Quelles sont les langues officielles de l'UE ?", answer: "L'UE compte 24 langues officielles, dont l'anglais, le français, l'allemand, et l'espagnol." },

  // ─── VALEURS────────────────────────────────────────────────────────────────────
  { id: "v03", theme: "valeurs", question: "C’est quoi le Blasphème ?", answer: "Le blasphème désigne une parole, un acte ou un geste qui offense ou manque de respect à une religion, à ses croyances, ou à ses symboles sacrés, autrement dit, critiquer une idée une religion ou une croyance. Selon les cultures et les religions, ce qui est considéré comme blasphématoire peut varier." },

  { id: "v05", theme: "valeurs", question: "c’est quoi la presse Satirique ?", answer: "La presse satirique est un type de presse qui utilise l'humour, l'ironie et l'exagération pour critiquer et se moquer des événements politiques, sociaux ou culturels. Elle vise souvent à dénoncer des abus, des injustices ou des comportements absurdes, tout en provoquant la réflexion." },
  { id: "v06", theme: "valeurs", question: "Les valeurs de votre religion se heurtent-elles avec les valeurs de la France ?", answer: "Non, les valeurs de ma religion sont compatibles avec les valeurs de la France, notamment celles de la laïcité et de la tolérance." },
  { id: "v07", theme: "valeurs", question: "La loi sur le mariage pour tous a été adoptée sous quel président de la république ?", answer: "La loi sur le mariage pour tous a été adoptée sous la présidence de François Hollande,", date: "17 mai 2013", president: "François Hollande" },
  { id: "v08", theme: "valeurs", question: "La loi sur le mariage pour tous a été portée par quel ancien ministre?", answer: "La loi sur le mariage pour tous a été portée par l’ancienne ministre de la Justice, Christiane Taubira.", date: "17 mai 2013", president: "François Hollande" },
  { id: "v09", theme: "valeurs", question: "Que s’est-il passé en France le 13 novembre 2015 ?", answer: "Le 13 novembre 2015, la France a été frappée par une série d’attentats terroristes à Paris et SaintDenis, faisant de nombreuses victimes.", date: "13 novembre 2015", president: "François Hollande" },
  { id: "v10", theme: "valeurs", question: "Quelles sont les conséquences des attentats du 13 novembre 2015 ?", answer: "Ces événements ont conduit à un renforcement des mesures de sécurité et à des actions contre le terrorisme en France et en Europe." },
  { id: "v11", theme: "geographie", question: "Combien de médailles la France a-t-elle remportées aux Jeux Olympiques de Paris 2024 ?", answer: "La France a remporté 64 médailles au total." },
  { id: "v12", theme: "geographie", question: "Combien de médailles d'or, d'argent et de bronze la France a-t-elle obtenues ?", answer: " 16 médailles d'or  26 médailles d'argent  22 médailles de bronze" },
  { id: "v13", theme: "geographie", question: "Citez quelques champions français aux Jeux Olympiques de Paris 2024 ?", answer: " Léon Marchand (Natation) : 4 médailles d'or, 1 médaille de bronze.  Teddy Riner (Judo) : 1 médaille d'or.  Pauline Ferrand-Prévot (VTT) : 1 médaille d'or.  Les athlètes français en canoë-kayak ont également décroché plusieurs médailles." },
  { id: "v14", theme: "geographie", question: "Quand ont eu lieu les Jeux Olympiques de Paris 2024 ?", answer: "Les Jeux ont eu lieu du 26 juillet au 11 août 2024." },
  { id: "v15", theme: "geographie", question: "Avez-vous regardé ou assisté aux Jeux Olympiques de Paris 2024 ?", answer: "La cérémonie d’ouverture des Jeux Olympiques de Paris 2024 a marqué les esprits par son format inédit sur la Seine, offrant un spectacle grandiose mêlant histoire, culture et modernité. Saluée pour son audace et sa mise en scène innovante, elle a néanmoins suscité quelques débats sur certains choix artistiques." },
  { id: "v16", theme: "valeurs", question: "Qu’est-ce que le mouvement #MeToo ?", answer: "Le mouvement #MeToo est un mouvement mondial contre les violences sexistes et sexuelles, encourageant la libération de la parole des victimes." },
  { id: "v17", theme: "valeurs", question: "Que s’est-il passé lors de l’affaire Samuel Paty ?", answer: "Il a été victime d’une attaque terroriste après avoir été la cible d’une campagne de haine sur les réseaux sociaux liée à un cours qu’il donnait sur la liberté d’expression." },
  { id: "v18", theme: "valeurs", question: "Pourquoi son assassinat a-t-il marqué la société française ?", answer: "Son assassinat a profondément choqué la France car il symbolise une attaque contre les valeurs fondamentales de la République, notamment la liberté d’expression et la laïcité." },
  { id: "v19", theme: "valeurs", question: "Quelle a été la réaction des autorités françaises ?", answer: "Les autorités ont condamné fermement cet acte, renforcé la lutte contre l’extrémisme et organisé des hommages nationaux en mémoire de Samuel Paty." },
  { id: "v20", theme: "valeurs", question: "Quels sont les principes et les valeurs de la République ? La devise de la France ?", answer: "Les valeurs de la République sont Liberté, Égalité, Fraternité, qui est également la devise de la France. Ces principes de la République comprennent son caractère indivisible, laïque, démocratique et social, tels que définis par la Constitution du 4 octobre 1958." },
  { id: "v21", theme: "valeurs", question: "Peut-on rajouter une quatrième valeur ? Si oui laquelle ?", answer: "Oui la laïcité, la laïcité est un principe fondamental de la République française, qui comporte deux volets importants :  L'État se doit d'être neutre envers les religions et ne doit favoriser aucune religion particulière. La religion relève de la sphère privée de chaque individu." },
  { id: "v22", theme: "valeurs", question: "Quel est l'emblème de la France ?", answer: "L'emblème de la France est le drapeau tricolore composé des couleurs rouge, bleue et blanche." },
  { id: "v23", theme: "valeurs", question: "Quels sont les symboles de la République?", answer: "Les symboles de la République comprennent Le drapeau, L'hymne national, Marianne, la devise : Liberté Egalité Fraternité, Le 14 juillet, Le coq, Le faisceau de licteur, Le sceau." },
  { id: "v24", theme: "valeurs", question: "Qui est Marianne ?", answer: "Marianne est une figure allégorique féminine qui incarne la République française. Elle représente les valeurs républicaines telles que la liberté, l'égalité et la fraternité. Marianne est souvent représentée avec un bonnet phrygien, qui symbolise la liberté, et elle est présentée dans chaque mairie." },
  { id: "v25", theme: "valeurs", question: "Est-il permis de porter des signes religieux en public en France ?", answer: "En France, il est permis de porter des signes religieux dans les espaces publics, mais il existe des restrictions dans les écoles publiques et pour les fonctionnaires en fonction, afin de respecter la laïcité." },
  { id: "v26", theme: "valeurs", question: "Citez un monument historique connu de votre choix et présentez-le ?", answer: "La Tour Eiffel est l’un des monuments les plus emblématiques de la France. Située à Paris, elle a été construite par Gustave Eiffel pour l’Exposition universelle de 1889." },
  { id: "v27", theme: "valeurs", question: "Quelles sont les principales caractéristiques de la Tour Eiffel ?", answer: "La Tour Eiffel mesure 330 mètres de haut, est construite en fer puddlé et pèse 10 100 tonnes." },
  { id: "v28", theme: "valeurs", question: "Pourquoi est-elle célèbre ?", answer: " Elle représente le savoir-faire français en ingénierie.  Elle attire plus de 6 millions de visiteurs par an.  Elle est un symbole mondial de la France et de Paris." },
  { id: "v29", theme: "valeurs", question: "Comment est-elle souvent appelée?", answer: "La tour Eiffel est souvent appelée La Grande Dame de Fer." },
  { id: "v30", theme: "valeurs", question: "Quel célèbre musée de Paris abrite la Joconde ?", answer: "Le musée du Louvre abrite la Joconde" },
  { id: "v31", theme: "valeurs", question: "Qui est Molière ?", answer: "Un célèbre dramaturge français du XVIIe (17) siècle, auteur du Malade Imaginaire et du Tartuffe…" },
  { id: "v32", theme: "valeurs", question: "Citez quelques marques française de la haute couture ?", answer: "La mode de luxe créée par de grands couturiers comme Chanel, Dior et Yves Saint Laurent." },
  { id: "v33", theme: "valeurs", question: "Quels sont quelques musées célèbres en France ?", answer: "Le Louvre, le Musée d’Orsay et le Centre Pompidou." },
  { id: "v34", theme: "valeurs", question: "Qui a peint la Joconde et où est-elle exposée ?", answer: "Léonard de Vinci, et elle est exposée au musée du Louvre." },
  { id: "v35", theme: "valeurs", question: "Qui est l'auteur du roman \"Madame Bovary\" ?", answer: "Gustave Flaubert." },
  { id: "v36", theme: "valeurs", question: "Question : Citez quelques grands auteurs français connus et leurs œuvres.", answer: " Molière : Le Misanthrope Une comédie qui critique la société et les faux-semblants, mettant en scène le personnage d'Alceste, un homme qui déteste l'hypocrisie.  Émile Zola : Germinal Un roman naturaliste qui dépeint les luttes des mineurs dans le nord de la France au XIXe siècle." },
  { id: "v37", theme: "valeurs", question: "Qui a construit l’Arc de Triomphe ?", answer: "L'Arc de Triomphe, situé sur les Champs-Élysées est construit par Napoléon 1er en 1806." },
  { id: "v38", theme: "valeurs", question: "Quelle cathédrale gothique est située sur l'île de la Cité à Paris ?", answer: "La cathédrale Notre-Dame de Paris est située sur l'île de la Cité." },
  { id: "v39", theme: "valeurs", question: "Quel est le nom de la célèbre basilique située sur la colline de Montmartre à Paris ?", answer: "La basilique du Sacré-Cœur est située sur la colline de Montmartre." },
  { id: "v40", theme: "valeurs", question: "Qui est Jean-Paul Sartre ?", answer: "Jean-Paul Sartre était un philosophe, écrivain et figure majeure de l’existentialisme. Il est l'auteur de nombreuses œuvres philosophiques et littéraires, dont L'Être et le Néant et Les Mots. Il a également refusé le prix Nobel de littérature en 1964." },
  { id: "v41", theme: "valeurs", question: "Citez un film français et son acteur principal.", answer: "Film : Intouchables, acteur principal : François Cluzet (qui joue le rôle de Philippe)" },
  { id: "v43", theme: "valeurs", question: "Citez une série française et son acteur principal.", answer: "Série: HPI, actrice principale : Audrey Fleurot (qui joue le rôle de Morgane Alvaro)" },
  { id: "v45", theme: "valeurs", question: "Qui est Simone de Beauvoir ?", answer: "Simone de Beauvoir était une philosophe, écrivaine et militante féministe française. Elle est l'autrice de Le Deuxième Sexe, un ouvrage fondamental sur les inégalités de genre et l'émancipation des femmes." },
  { id: "v46", theme: "valeurs", question: "Qui est Antoine Lavoisier ?", answer: "Antoine Lavoisier est un chimiste français du XVIIIe (18) siècle, souvent appelé le \"père de la chimie moderne\". Il a découvert la loi de la conservation de la masse et a identifié l'oxygène comme un élément fondamental de la combustion." },
  { id: "v47", theme: "valeurs", question: "Quel est le dernier film que vous avez vu au cinéma ? Qui est le réalisateur et l'acteur principal ?", answer: "Cela dépend des goûts et de l'actualité du cinéma, mais par exemple : Le dernier film que j'ai vu est Le Comte de Monte-Cristo, réalisé par Matthieu Delaporte et Alexandre de La Patellière. L'acteur principal est Pierre Niney, qui interprète le rôle d'Edmond Dantès." },
  { id: "v48", theme: "valeurs", question: "Quelle est la capacité du Stade de France ?", answer: "Environ 80 000 spectateurs." },
  { id: "v49", theme: "valeurs", question: "Nommez deux grands scientifiques français.", answer: "Marie Curie et Louis Pasteur." },
  { id: "v50", theme: "valeurs", question: "Qui est Louis Pasteur ?", answer: "Louis Pasteur était un scientifique français, pionnier dans la découverte des micro-organismes et dans le développement de vaccins. Il a révolutionné la médecine avec ses recherches sur la fermentation et la pasteurisation." },
  { id: "v51", theme: "valeurs", question: "Citez quelques chefs cuisiniers célèbres.", answer: "Paul Bocuse, Alain Ducasse, Joël Robuchon, Philippe Etchebest, Hélène Darroze et Michel Sarran." },
  { id: "v52", theme: "valeurs", question: "Qu'est-ce que la Francophonie ?", answer: "L'ensemble des personnes et pays partageant la langue française." },
  { id: "v53", theme: "valeurs", question: "Nommez un célèbre festival de cinéma qui se tient annuellement en France ?", answer: "Le Festival de Cannes." },
  { id: "v54", theme: "valeurs", question: "Quel est le nombre de restaurants étoilés Michelin en France ?", answer: "La France possède plus de 600 restaurants étoilés Michelin, dont plusieurs 3 étoiles, ce qui en fait l'un des pays avec le plus grand nombre de restaurants de haute gastronomie." },
  { id: "v55", theme: "valeurs", question: "Quel musée français est dédié à l'art moderne et contemporain ?", answer: "Le Centre Pompidou." },
  { id: "v56", theme: "valeurs", question: "Citez quelques plats typiques de la cuisine française ?", answer: "Coq au vin, Bœuf bourguignon, Ratatouille, Tartiflette, Soupe à l'oignon, Quiche Lorraine Crêpes, Bouillabaisse…" },
  { id: "v57", theme: "valeurs", question: "Qu'est-ce que la Fête de la Musique ?", answer: "Un événement annuel célébrant la musique vivante le 21 juin, jour du solstice d'été." },
  { id: "v58", theme: "valeurs", question: "Qu'est-ce que l'AMF (Autorité des marchés financiers) ?", answer: "L'organisme de régulation de la bourse en France." },
  { id: "v59", theme: "valeurs", question: "Quel écrivain français a remporté le Prix Nobel de littérature en 2014 ?", answer: "Patrick Modiano." },
  { id: "v60", theme: "valeurs", question: "Qu'est-ce que le CNRS ?", answer: "Le Centre National de la Recherche Scientifique, une organisation gouvernementale de recherche en France." },
  { id: "v61", theme: "valeurs", question: "Comment la France a-t-elle influencé la cuisine mondiale ?", answer: "La France a grandement influencé la cuisine mondiale par ses techniques culinaires, ses écoles de cuisine, son système de restaurants et ses innovations gastronomiques. Des chefs comme Paul Bocuse, Alain Ducasse et Joël Robuchon ont également contribué à faire connaître la cuisine française dans le monde entier." },
  { id: "v62", theme: "valeurs", question: "Quelles est la place France dans la pâtisserie au niveau mondial?", answer: "La France est un leader mondial dans la pâtisserie en raison de son histoire, de ses techniques de fabrication uniques et de ses créations emblématiques comme les éclairs, les macarons, les millefeuilles et les croissants. Les écoles de pâtisserie françaises, comme Le Cordon Bleu, sont aussi réputées mondialement." },
  { id: "v63", theme: "valeurs", question: "Quelle est la bande dessinée la plus connue en France ?", answer: "Astérix et Obélix" },
  { id: "v64", theme: "valeurs", question: "Qui est le créateur de la série de bandes dessinées Astérix ?", answer: "René Goscinny et Albert Uderzo." },
  { id: "v65", theme: "valeurs", question: "Citez quelques sportifs français connu et leur discipline respective :", answer: "Kylian Mbappé (football), Tony Parker (Basket), Clarisse Agbegnenou (judo), Antoine Dupont (Rugby), Camille Lacourt (Natation)" },
  { id: "v66", theme: "valeurs", question: "Qu'ont en commun les pays européens ?", answer: "Les pays européens partagent une histoire, des valeurs culturelles, économiques et politiques similaires. La plupart sont membres de l'Union européenne (UE), qui favorise la coopération économique, politique et sociale. Ils adhèrent à des principes communs comme la démocratie, les droits de l'homme et l'état de droit." },
  { id: "v67", theme: "valeurs", question: "Quelle est la devise de la République française ?", answer: "\"Liberté, Égalité, Fraternité\" — adoptée depuis la Révolution de 1789, inscrite dans la Constitution et visible sur les bâtiments officiels." },
  { id: "v68", theme: "valeurs", question: "Qu'est-ce que la laïcité à la française ?", answer: "Principe constitutionnel qui sépare l'État de toute religion. L'État ne reconnaît ni ne finance aucun culte. Chacun est libre de croire ou non, mais la religion reste dans la sphère privée." },
  { id: "v69", theme: "valeurs", question: "Que signifie le principe d'égalité en France ?", answer: "Tous les citoyens sont égaux devant la loi, sans distinction d'origine, de sexe ou de religion. L'égalité homme-femme est une valeur fondamentale de la République." },
  { id: "v70", theme: "valeurs", question: "Qu'est-ce que la fraternité comme valeur républicaine ?", answer: "Principe de solidarité entre citoyens. Elle se traduit par la protection sociale, l'entraide et le refus des discriminations. C'est le \"vivre ensemble\" à la française." },
  { id: "v71", theme: "valeurs", question: "Quelle est la place de la religion dans l'État français ?", answer: "La France est un État laïc. La loi de 1905 sépare l'Église de l'État : l'État ne finance aucun culte et la religion relève de la sphère privée des individus." },
  { id: "v72", theme: "valeurs", question: "Quels sont les symboles de la République française ?", answer: "Le drapeau bleu-blanc-rouge, la Marianne, la devise \"Liberté, Égalité, Fraternité\", l'hymne national La Marseillaise et le coq gaulois." },
  { id: "v73", theme: "valeurs", question: "Qu'est-ce que La Marseillaise ?", answer: "L'hymne national français, composé en 1792 par Rouget de Lisle pendant la Révolution. Entonné lors des cérémonies officielles et événements sportifs internationaux." },
  { id: "v74", theme: "valeurs", question: "Qu'est-ce que le principe de non-discrimination en France ?", answer: "Nul ne peut être traité différemment en raison de son origine, sexe, religion, handicap ou orientation sexuelle. La discrimination est un délit puni par la loi." },
  { id: "v75", theme: "valeurs", question: "Pourquoi dit-on que la France est une République indivisible ?", answer: "Parce qu'il n'y a qu'un seul peuple français, une seule loi pour tous. Il n'existe pas de droits particuliers fondés sur l'appartenance régionale ou religieuse." },
  { id: "v76", theme: "valeurs", question: "Qu'est-ce que la liberté d'expression en France ?", answer: "Droit fondamental de s'exprimer librement, sans censure préalable. Elle a des limites légales : l'incitation à la haine, la diffamation et les propos racistes sont interdits." },
  { id: "v77", theme: "valeurs", question: "Que représente le drapeau bleu-blanc-rouge ?", answer: "Le tricolore symbolise la Révolution française et les valeurs de la République. Le bleu et le rouge sont les couleurs de Paris, le blanc celles de la royauté française." },
  { id: "v78", theme: "valeurs", question: "Qu'est-ce que la Marianne ?", answer: "Figure allégorique féminine symbolisant la République française. Elle représente la liberté et la raison. Son buste orne toutes les mairies et ses effigies les documents officiels." },
  { id: "v79", theme: "valeurs", question: "Qu'est-ce que le principe de fraternité inscrit dans la Constitution ?", answer: "La fraternité est l'une des trois valeurs fondamentales de la République. Le Conseil constitutionnel a reconnu en 2018 qu'elle implique la liberté d'aider autrui sans discrimination." },
  { id: "v80", theme: "valeurs", question: "Qu'est-ce que l'égalité hommes-femmes en France ?", answer: "Valeur constitutionnelle depuis 1946. La loi interdit toute discrimination fondée sur le sexe. La parité en politique, l'égalité salariale et la lutte contre les violences sexistes sont des priorités." },
  { id: "v81", theme: "valeurs", question: "Qu'est-ce que la neutralité religieuse à l'école ?", answer: "Dans les établissements scolaires publics, les élèves ne peuvent porter de signes religieux ostensibles (loi de 2004). Les enseignants doivent également respecter la neutralité religieuse." },
  { id: "v82", theme: "valeurs", question: "Qu'est-ce que la Déclaration des droits de l'homme de 1948 ?", answer: "Texte adopté par l'ONU le 10 décembre 1948, rédigé notamment par René Cassin. Elle proclame les droits fondamentaux universels : vie, liberté, dignité, interdiction de la torture." },
  { id: "v83", theme: "valeurs", question: "Qu'est-ce que la Convention européenne des droits de l'homme ?", answer: "Traité international adopté en 1950 par le Conseil de l'Europe. Il garantit les droits fondamentaux des citoyens européens, protégés par la Cour européenne des droits de l'homme à Strasbourg." },
  { id: "v84", theme: "valeurs", question: "Qu'est-ce que la Cour européenne des droits de l'homme ?", answer: "Juridiction internationale siégeant à Strasbourg, compétente pour juger les violations des droits fondamentaux par les États membres du Conseil de l'Europe, dont la France." },
  { id: "v85", theme: "valeurs", question: "Qu'est-ce que la gastronomie française classée à l'UNESCO ?", answer: "Le repas gastronomique des Français a été inscrit au patrimoine culturel immatériel de l'UNESCO en 2010. Il célèbre le goût du bien manger et du partage à la table française." },
  { id: "v86", theme: "valeurs", question: "Qu'est-ce que la loi Toubon sur la langue française ?", answer: "Loi de 1994 qui impose l'usage du français dans les services publics, la publicité, l'enseignement et les contrats de travail en France. Elle protège la langue française face à l'anglicisme." },
  { id: "v87", theme: "valeurs", question: "Qu'est-ce que la charte de la laïcité à l'école ?", answer: "Document officiel affiché dans toutes les écoles publiques françaises, expliquant le principe de laïcité, les droits et devoirs de chacun dans l'établissement scolaire." },
  { id: "v88", theme: "valeurs", question: "Qu'est-ce que le devoir de mémoire en France ?", answer: "Obligation morale et civique de ne pas oublier les pages sombres de l'histoire (Shoah, esclavage, guerres). Des commémorations officielles entretiennent le souvenir des victimes." },
  { id: "v89", theme: "valeurs", question: "Quelles sont les principales commémorations nationales en France ?", answer: "Le 11 novembre (armistice 1918), le 8 mai (victoire 1945), le 14 juillet (Fête nationale), le 27 janvier (mémoire de la Shoah) et le 10 mai (mémoire de l'esclavage)." },
  { id: "v90", theme: "valeurs", question: "Qu'est-ce que la politique d'intégration républicaine en France ?", answer: "La France favorise l'assimilation des immigrés aux valeurs républicaines via le Contrat d'Intégration Républicaine (CIR) : cours de français, formation civique, adhésion aux valeurs de la République." },
  { id: "v91", theme: "valeurs", question: "Qu'est-ce que le Contrat d'Intégration Républicaine (CIR) ?", answer: "Signé par tout primo-arrivant légal en France, il comprend une formation civique aux valeurs républicaines et des cours de français. Il est obligatoire pour obtenir le renouvellement du titre de séjour." },
  { id: "v92", theme: "valeurs", question: "Qu'est-ce que la littérature française ?", answer: "Riche tradition littéraire comptant des géants comme Victor Hugo, Molière, Voltaire, Balzac, Zola, Proust, Camus. La France est le pays qui a remporté le plus de Prix Nobel de littérature." },
  { id: "v93", theme: "valeurs", question: "Qu'est-ce que le cinéma français ?", answer: "Né à Lyon avec les frères Lumière en 1895, le cinéma français est une industrie culturelle majeure. La Palme d'Or au Festival de Cannes est la récompense cinématographique la plus prestigieuse." },
  { id: "v94", theme: "valeurs", question: "Qu'est-ce que la peinture impressionniste française ?", answer: "Mouvement artistique né en France au XIXe siècle avec Monet, Renoir, Degas et Pissarro. L'impressionnisme a révolutionné l'art en privilégiant la lumière et la sensation sur le réalisme." },
  { id: "v95", theme: "valeurs", question: "Qu'est-ce que le Festival de Cannes ?", answer: "Festival international du cinéma organisé chaque année en mai à Cannes. La Palme d'Or est sa récompense suprême. C'est l'un des événements culturels les plus médiatisés au monde." },
  { id: "v96", theme: "valeurs", question: "Qu'est-ce que la cuisine française ?", answer: "Reconnue dans le monde entier, la cuisine française est inscrite au patrimoine de l'UNESCO. Elle valorise les produits locaux, les techniques culinaires raffinées et le partage autour de la table." },
  { id: "v97", theme: "valeurs", question: "Qu'est-ce que le Tour de France cycliste ?", answer: "Grande course cycliste annuelle en juillet, la plus célèbre au monde. Créée en 1903, elle traverse la France en environ 3 semaines et symbolise le sport et le patrimoine français." },
  { id: "v98", theme: "valeurs", question: "Qu'est-ce que la laïcité dans l'espace public ?", answer: "Dans l'espace public, la liberté de conscience et d'expression est garantie. Il est interdit de contraindre quelqu'un dans ses croyances. La loi encadre le port de certains signes religieux dans des contextes spécifiques." },
  { id: "v99", theme: "valeurs", question: "Qu'est-ce que la lutte contre le racisme et l'antisémitisme en France ?", answer: "La France dispose de lois strictes (loi Pleven 1972, loi Gayssot 1990) condamnant le racisme, l'antisémitisme et la xénophobie. Des associations comme SOS Racisme et la LICRA combattent ces phénomènes." },
  { id: "v100", theme: "valeurs", question: "Qu'est-ce que le patrimoine naturel et culturel protégé en France ?", answer: "La France compte 54 sites classés au patrimoine mondial de l'UNESCO (cathédrale de Chartres, abbaye du Mont-Saint-Michel, châteaux de la Loire, etc.). Elle figure parmi les pays les plus représentés." },
  { id: "v101", theme: "valeurs", question: "Qu'est-ce que la solidarité nationale en France ?", answer: "Principe fondamental selon lequel l'État et les citoyens soutiennent les plus vulnérables via l'impôt et la protection sociale. La solidarité se traduit aussi par le bénévolat et l'engagement associatif." },
  { id: "v102", theme: "valeurs", question: "Qu'est-ce que les Restos du Cœur ?", answer: "Association caritative fondée par Coluche en 1985 qui distribue gratuitement des repas et produits alimentaires aux personnes en difficulté. Elle compte des millions de bénévoles à travers la France." },
  { id: "v103", theme: "valeurs", question: "Qu'est-ce que la Croix-Rouge française ?", answer: "Association humanitaire qui porte secours aux victimes de catastrophes et de conflits. Elle gère des établissements sociaux, des formations aux premiers secours et des services d'aide à domicile." },
  { id: "v104", theme: "valeurs", question: "Qu'est-ce que l'engagement associatif en France ?", answer: "La France compte 1,5 million d'associations et 12 millions de bénévoles. L'engagement associatif est une expression de la fraternité républicaine et du vivre-ensemble." },
  { id: "v105", theme: "valeurs", question: "Qu'est-ce que le modèle social français ?", answer: "Système combinant économie de marché et protection sociale forte : Sécurité sociale, assurance chômage, retraites par répartition, service public d'éducation et de santé gratuits ou peu coûteux." },
  { id: "v106", theme: "valeurs", question: "Qu'est-ce que les droits des enfants en France ?", answer: "La France a ratifié la Convention internationale des droits de l'enfant (1989). Elle garantit le droit à l'éducation, à la santé, à la protection contre les violences et à être entendu dans les décisions qui le concernent." },
  { id: "v107", theme: "valeurs", question: "Qu'est-ce que l'hymne européen et quel est son lien avec la France ?", answer: "L'Ode à la Joie de Beethoven est l'hymne de l'Union européenne, adopté en 1985. La France, pays fondateur de l'UE, adhère aux valeurs européennes de paix, liberté et démocratie." },
  { id: "v108", theme: "valeurs", question: "Qu'est-ce que le Panthéon à Paris ?", answer: "Monument parisien qui abrite les cendres des grandes personnalités qui ont contribué à la France : Victor Hugo, Voltaire, Marie Curie, Simone Veil. C'est un temple de la mémoire nationale républicaine." },
  { id: "v109", theme: "valeurs", question: "Qu'est-ce que la Légion d'honneur ?", answer: "Ordre national français créé par Napoléon en 1802, c'est la plus haute distinction honorifique en France. Elle récompense des mérites éminents rendus à la nation civils ou militaires." },
  { id: "v110", theme: "valeurs", question: "Qu'est-ce que la liberté de réunion en France ?", answer: "Droit fondamental qui permet aux citoyens de se rassembler pacifiquement, notamment pour manifester. Les réunions publiques doivent être déclarées à la préfecture au préalable." },
  { id: "v111", theme: "valeurs", question: "Qu'est-ce que la neutralité du service public en France ?", answer: "Les services publics doivent traiter tous les usagers de la même façon, sans favoritisme ni discrimination. Les agents publics doivent respecter une stricte neutralité religieuse et politique." },
  { id: "v112", theme: "valeurs", question: "Qu'est-ce que vous pensez de la polygamie ?", answer: "La polygamie est strictement interdite en France. Le mariage y est fondé sur l'égalité entre les époux et ne peut unir qu'une seule personne à une autre. Contracter un second mariage tout en étant déjà marié(e) est un délit pénal appelé bigamie. Cette interdiction reflète les valeurs françaises d'égalité et de respect mutuel entre conjoints." },
  { id: "v113", theme: "histoire", question: "Qu'est-ce qui s'est passé avec Charlie Hebdo ?", answer: "Le 7 janvier 2015, deux terroristes islamistes ont attaqué la rédaction du journal satirique Charlie Hebdo à Paris, tuant 12 personnes dont des dessinateurs et journalistes. Ces attentats ont été commis en représailles à des caricatures publiées par le journal. Ils ont profondément choqué la France et déclenché un immense élan de solidarité autour de la liberté de la presse et de la liberté d'expression, valeurs fondamentales de la République. En France, on a le droit de critiquer et de se moquer, y compris des religions — c'est la liberté d'expression. La violence n'est jamais une réponse acceptable." },

  // ─── GEOGRAPHIE─────────────────────────────────────────────────────────────────
  { id: "g01", theme: "geographie", question: "Qui était Samuel Paty ?", answer: "Samuel Paty était un enseignant d’histoire-géographie en France, assassiné en octobre 2020 après avoir montré des caricatures dans un cours sur la liberté d’expression." },
  { id: "g02", theme: "geographie", question: "Citez le nom du président de votre région ?", answer: "Exemple : Valérie Pécresse – Région île de France ; Xavier Bertrand : Hauts-de-France…" },
  { id: "g03", theme: "geographie", question: "Comment sont élus les présidents de région et de départements ?", answer: "Les présidents du conseil régional et du conseil départemental sont élus au suffrage universel indirect, car ils ne sont pas élus directement par les citoyens mais par les conseillers régionaux et départementaux. En cas de décès, démission ou empêchement du Président de la République, le Président du Sénat assure l’intérim." },
  { id: "g04", theme: "geographie", question: "Citez un plat typique de votre région ?", answer: "Provence-Alpes-Côte d'Azur : La ratatouille – Bretagne : Les crêpes – Normandie : Le camembert – Bourgogne : Le bœuf bourguignon – Alsace : La choucroute – Auvergne-Rhône-Alpes : La fondue savoyarde – Occitanie : Le cassoulet …" },
  { id: "g05", theme: "geographie", question: "Citez quelques auteurs français récents et leurs œuvres ?", answer: " Jean d'Ormesson : La Gloire de l'Empire Ce roman mêle fiction et réflexion historique, proposant une vision de l’histoire à travers les yeux d’un personnage imaginaire, tout en offrant une réflexion sur la quête du pouvoir et de la gloire." },
  { id: "g06", theme: "geographie", question: "Quel est le festival de musique électronique célèbre en France ?", answer: "Les Nuits Sonores à Lyon." },
  { id: "g07", theme: "geographie", question: "Pouvez-vous citer quelques pays limitrophes de la France ?", answer: "La France partage ses frontières avec l'Espagne, l'Andorre, l'Italie, la Suisse, l'Allemagne, le Luxembourg, la Belgique, et Monaco." },
  { id: "g08", theme: "geographie", question: "Quel est le plus grand lac naturel de France ?", answer: "Le Lac du Bourget." },
  { id: "g09", theme: "geographie", question: "Quelle est la plus vieille institution financière encore en activité en France ?", answer: "La Banque de France, fondée en 1800." },
  { id: "g10", theme: "geographie", question: "Quel monument historique est situé sur l'île de la Cité à Paris ?", answer: "La Cathédrale Notre-Dame de Paris." },
  { id: "g11", theme: "geographie", question: "Quel est le nom de l'aéroport le plus fréquenté de France ?", answer: "L'aéroport Charles-de-Gaulle." },
  { id: "g12", theme: "geographie", question: "Pouvez-vous nommer des départements d’outre-mer (DOM) ?", answer: "Les départements d’outre-mer (DOM) comprennent la Guadeloupe, la Martinique, la Guyane, La Réunion et Mayotte." },
  { id: "g13", theme: "geographie", question: "Pouvez-vous donner des exemples de départements français ?", answer: "Parmi les départements français, on peut citer le Jura, Paris, l'Ardèche, la Loire, l'Isère, la HauteSavoie, le Nord, le Pas- de-Calais, et bien d'autres." },
  { id: "g14", theme: "geographie", question: "Pouvez-vous nommer quelques régions françaises ?", answer: "En France, on peut mentionner des régions telles que la Bourgogne-Franche-Comté, la Bretagne, la Normandie, la Corse, les Hauts-de-France, l'Auvergne-Rhône-Alpes, l'Île- de-France, les Pays de la Loire, le Centre-Val de Loire, le Grand Est, la Nouvelle-Aquitaine, l'Occitanie, ProvenceAlpes-Côte dʼAzur, ainsi que les ré." },
  { id: "g15", theme: "geographie", question: "Pouvez-vous citer des noms de grandes villes françaises ?", answer: "Parmi les grandes villes françaises, on peut citer Paris, Marseille, Lyon, Toulouse, Nice, Nantes, Montpellier, Strasbourg, Bordeaux et Lille." },
  { id: "g16", theme: "geographie", question: "Avez-vous visité des territoires d’Outre-mer ?", answer: "Non, mais je connais leur importance pour la France. / Oui, j’ai visité (nom du territoire) et découvert sa culture." },
  { id: "g17", theme: "geographie", question: "Quelle est la différence entre un DOM-TOM et une région d’Outre-mer ?", answer: "Les DOM (Départements d’Outre-mer) sont comme les départements en France : ils suivent les mêmes lois que la métropole. Les TOM (Territoires d’Outre-mer) ont plus d’autonomie, donc ils peuvent avoir des règles différentes. Aujourd’hui, on utilise plutôt le terme \"collectivités d’Outre-mer\" pour parler de ces territoires." },
  { id: "g18", theme: "geographie", question: "Quelles sont les chaînes de montagnes qui séparent la France de ses voisins ?", answer: " France - Espagne : Les Pyrénées.  France - Italie : Les Alpes.  France - Suisse : Le Jura et les Alpes." },
  { id: "g19", theme: "geographie", question: "Quelle est la ville d'origine de la tarte Tatin ?", answer: "Lamotte-Beuvron." },
  { id: "g20", theme: "geographie", question: "Quelle est la hauteur de la Tour Eiffel ?", answer: "Environ 324 mètres." },
  { id: "g21", theme: "geographie", question: "Quel est le nom du Parc national situé en Guadeloupe ?", answer: "Le Parc national de la Guadeloupe." },
  { id: "g22", theme: "geographie", question: "Qu'est-ce que le Mont-Saint-Michel ?", answer: "Un îlot rocheux en Normandie, célèbre pour son abbaye et classé au patrimoine mondial de l'UNESCO." },
  { id: "g23", theme: "geographie", question: "Combien y a-t-il de départements et régions d’Outre-mer (DOM-ROM) ?", answer: "Il y a 5 départements et régions d’Outre-mer (DROM) : Guadeloupe, Martinique, Guyane, Réunion, et Mayotte Ces territoires ont les mêmes lois que la France métropolitaine." },
  { id: "g24", theme: "geographie", question: "Quelle est la différence entre les COM et les DROM ?", answer: "Les DROM (Départements et Régions d’Outre-mer) : Ce sont des départements et régions qui fonctionnent comme en métropole. Les mêmes lois et règles s’appliquent partout en France. Les COM (Collectivités d’Outre-mer) : Ces territoires ont plus d’autonomie, donc ils peuvent avoir des lois et règles différentes de la France métropolitaine." },
  { id: "g25", theme: "geographie", question: "Quel est le plus grand château de la Loire ?", answer: "Le château de Chambord." },
  { id: "g26", theme: "geographie", question: "Quelles sont les mers et océans qui entourent la France ?", answer: "En métropole : La Manche, la mer du Nord, l’océan Atlantique et la mer Méditerranée. Outre-mer : L’océan Indien, l’océan Pacifique, l’océan Atlantique, la mer des Caraïbes." },
  { id: "g27", theme: "geographie", question: "Citez des villes proches des grandes chaînes de montagnes en France.", answer: " Pyrénées : Pau, Perpignan, Tarbes.  Alpes : Grenoble, Chambéry, Annecy.  Jura : Besançon, Lons-le-Saunier.  Massif central : Clermont-Ferrand, Le Puy-en-Velay." },
  { id: "g28", theme: "geographie", question: "Quelle est la plus grande forêt de France ?", answer: "La forêt des Landes." },
  { id: "g29", theme: "geographie", question: "Quel est le point culminant de la France ?", answer: "Le Mont Blanc est le point culminant de la France." },
  { id: "g30", theme: "geographie", question: "Quel est le nom du désert situé dans le sud de la France ?", answer: "Le désert situé dans le sud de la France est le désert des Bardenas Reales." },
  { id: "g31", theme: "geographie", question: "Quelles sont les montagnes situées à la frontière entre la France et l'Espagne ?", answer: "Les Pyrénées sont les montagnes situées à la frontière entre la France et l'Espagne." },
  { id: "g32", theme: "geographie", question: "Quel est le nom de la chaîne de montagnes située en France qui est célèbre pour ses stations de ski ?", answer: "Les Alpes sont célèbres pour leurs stations de ski en France." },
  { id: "g33", theme: "geographie", question: "Quelle île française se trouve dans la mer Méditerranée, au large de la côte sud-est de la France ?", answer: "La Corse est une île française située dans la mer Méditerranée." },
  { id: "g34", theme: "geographie", question: "Quelle région française est connue pour ses vignobles et sa production de vin ?", answer: "La région de Bordeaux est célèbre pour ses vignobles et sa production de vin." },
  { id: "g35", theme: "geographie", question: "Quelle est la plus grande région forestière de France ?", answer: "La Forêt des Landes est la plus grande région forestière de France." },
  { id: "g36", theme: "geographie", question: "Quelle est la principale île volcanique française située dans l'océan Indien ?", answer: "La Réunion est la principale île volcanique française dans l'océan Indien." },
  { id: "g37", theme: "geographie", question: "Quel est le nom du détroit qui sépare la Corse de l'Italie ?", answer: "Le détroit qui sépare la Corse de l'Italie est le détroit de Bonifacio." },
  { id: "g38", theme: "geographie", question: "Quelle rivière traverse la ville de Lyon en France ?", answer: "Le Rhône traverse la ville de Lyon en France." },
  { id: "g39", theme: "geographie", question: "Quelle région est connue comme le berceau de la Préhistoire en France ?", answer: "La région connue comme le berceau de la Préhistoire en France est le Périgord, située en Dordogne, dans le sud- ouest du pays." },
  { id: "g40", theme: "geographie", question: "Citez quelques fleuves de France ?", answer: "La Seine, la Loire, le Rhône, la Garonne, le Rhin." },
  { id: "g41", theme: "geographie", question: "Quelles sont quelques grandes villes de France ?", answer: "Paris, Marseille, Lyon, Toulouse, Nice." },
  { id: "g42", theme: "geographie", question: "Quelles sont les principales chaînes de montagnes en France ?", answer: "Les Alpes, les Pyrénées, le Massif central, le Jura, les Vosges." },
  { id: "g43", theme: "geographie", question: "Quelles mers et océans bordent la France ?", answer: "La Manche, l'océan Atlantique, la mer Méditerranée, la mer du Nord.  À l'ouest, l'Océan Atlantique borde la France métropolitaine.  Au nord, la Manche sépare la France du Royaume-Uni.  Au sud, la Mer Méditerranée borde la France, principalement sur la côte d'Azur." },
  { id: "g44", theme: "geographie", question: "Citez quelques villes françaises et leurs régions respectives.", answer: "Paris - Île-de-France, Marseille - Provence-Alpes-Côte d'Azur, Lyon - Auvergne-Rhône-Alpes, Toulouse - Occitanie, Nice - Provence-Alpes-Côte d'Azur, Bordeaux - Nouvelle-Aquitaine, Lille - Hauts-deFrance, Nantes - Pays de la Loire, Strasbourg - Grand Est, Toulouse - Occitanie, Rennes - Bretagne, Dijon - Bourgogne-Franche-Comté" },
  { id: "g45", theme: "geographie", question: "Quelles sont les origines des principaux fleuves de France ?", answer: " La Loire : C'est le plus long fleuve de France, il prend sa source dans le Massif central, plus précisément dans le département de l'Allier, et se jette dans l'océan Atlantique.  La Seine : Elle prend sa source dans le plateau de Langres, en Haute-Marne, et traverse Paris avant de se jeter dans la Manche." },
  { id: "g46", theme: "geographie", question: "Quelles sont les frontières de la France d'outre-mer ?", answer: "Guyane : Frontière avec le Brésil et le Suriname, Saint-Martin : Frontière avec Sint Maarten (Pays-Bas), Saint-Pierre-et-Miquelon : Frontière maritime avec le Canada, Mayotte : Frontière maritime avec les Comores et Madagascar, Réunion : Pas de frontière terrestre, mais située à proximité de Madagascar, Nouvelle-Calédo." },
  { id: "g47", theme: "geographie", question: "C'est quoi l'espace Schengen ?", answer: "L'espace Schengen est un ensemble de pays européens qui ont aboli les contrôles aux frontières internes entre eux. Cela permet la libre circulation des personnes à l'intérieur de cet espace, facilitant les voyages et les échanges. Il comprend la plupart des pays de l'UE, ainsi que quelques pays non membres de l'UE." },
  { id: "g48", theme: "geographie", question: "Où se trouve le siège principal du Parlement européen ?", answer: "Le siège principal du Parlement européen est également à Bruxelles, en Belgique. Cependant, le Parlement européen a des sessions à Strasbourg, en France, où il se réunit périodiquement." },
  { id: "g49", theme: "geographie", question: "Quelle est la capitale de la France ?", answer: "Paris, siège du gouvernement, du Parlement et de la Présidence de la République. Avec environ 2 millions d'habitants dans la ville et 12 millions en Île-de-France." },
  { id: "g50", theme: "geographie", question: "Combien de régions métropolitaines compte la France ?", answer: "13 régions métropolitaines depuis la réforme de 2016, auxquelles s'ajoutent 5 régions et départements d'outre-mer (DROM) : Guadeloupe, Martinique, Guyane, Réunion et Mayotte." },
  { id: "g51", theme: "geographie", question: "Quels pays partagent une frontière terrestre avec la France ?", answer: "La Belgique, le Luxembourg, l'Allemagne, la Suisse, l'Italie, Monaco, l'Andorre et l'Espagne. La France est au carrefour de l'Europe occidentale." },
  { id: "g52", theme: "geographie", question: "Quel fleuve traverse Paris ?", answer: "La Seine. Elle traverse la capitale d'est en ouest. Paris est née sur l'île de la Cité, au milieu du fleuve. La Seine a joué un rôle majeur dans le développement commercial de la ville." },
  { id: "g53", theme: "geographie", question: "Quelle est la plus haute montagne de France et d'Europe occidentale ?", answer: "Le Mont-Blanc, situé dans les Alpes à la frontière franco-italienne, culmine à 4 808 mètres d'altitude. C'est le point culminant des Alpes et de toute l'Europe occidentale." },
  { id: "g54", theme: "geographie", question: "Qu'est-ce que les DROM (Départements et Régions d'Outre-Mer) ?", answer: "Territoires français situés hors d'Europe faisant partie intégrante de la République : Guadeloupe, Martinique, Guyane, Réunion et Mayotte. Leurs habitants sont citoyens français." },
  { id: "g55", theme: "geographie", question: "Quelle mer borde le sud de la France ?", answer: "La mer Méditerranée au sud-est. À l'ouest et au nord-ouest, la France est bordée par l'océan Atlantique et la Manche au nord." },
  { id: "g56", theme: "geographie", question: "Combien de départements compte la France métropolitaine ?", answer: "96 départements métropolitains, numérotés de 01 (Ain) à 95 (Val-d'Oise), plus le 75 pour Paris. Chaque département est administré par un conseil départemental." },
  { id: "g57", theme: "geographie", question: "Quelle est la ville surnommée la \"Capitale des Gaules\" ?", answer: "Lyon. Deuxième agglomération française, elle est aussi connue pour sa gastronomie, son histoire antique et ses traboules — ruelles typiques du Vieux-Lyon classé à l'UNESCO." },
  { id: "g58", theme: "geographie", question: "Quel est le plus long fleuve de France ?", answer: "La Loire, avec 1 012 km. Elle traverse le Massif central puis rejoint l'Atlantique à Saint-Nazaire. Son val est classé au patrimoine mondial de l'UNESCO." },
  { id: "g59", theme: "geographie", question: "Quelle est la superficie de la France métropolitaine ?", answer: "La France métropolitaine couvre environ 551 695 km², faisant d'elle le plus grand pays de l'Union européenne. En incluant les outre-mer, la France métropolitaine et ses territoires s'étendent sur 675 000 km²." },
  { id: "g60", theme: "geographie", question: "Quelles sont les 13 régions de France métropolitaine ?", answer: "Île-de-France, Normandie, Hauts-de-France, Grand Est, Bretagne, Pays de la Loire, Centre-Val de Loire, Bourgogne-Franche-Comté, Nouvelle-Aquitaine, Occitanie, Auvergne-Rhône-Alpes, PACA et Corse." },
  { id: "g61", theme: "geographie", question: "Quelle est la troisième ville de France ?", answer: "Marseille, avec environ 870 000 habitants. Fondée par les Grecs en 600 av. J.-C., c'est la plus ancienne ville de France. Elle est le premier port de commerce de la Méditerranée française." },
  { id: "g62", theme: "geographie", question: "Quelle ville est la capitale de la région Nouvelle-Aquitaine ?", answer: "Bordeaux, connue pour ses vins mondialement réputés (Saint-Émilion, Médoc, Sauternes). Le centre historique de Bordeaux est classé au patrimoine mondial de l'UNESCO." },
  { id: "g63", theme: "geographie", question: "Où se trouve le Mont-Saint-Michel ?", answer: "En Normandie, dans la baie du Mont-Saint-Michel, à la frontière entre la Normandie et la Bretagne. Cette abbaye médiévale sur un îlot rocheux est classée au patrimoine de l'UNESCO depuis 1979." },
  { id: "g64", theme: "geographie", question: "Qu'est-ce que la Corse ?", answer: "Île française de la mer Méditerranée, surnommée l'Île de Beauté. Elle est la 4e plus grande île de Méditerranée. Sa capitale est Ajaccio, ville natale de Napoléon Bonaparte. Elle a le statut de collectivité unique." },
  { id: "g65", theme: "geographie", question: "Quelle est la ville siège du Parlement européen ?", answer: "Strasbourg, en Alsace. Le Parlement européen y tient ses sessions plénières. Bruxelles est le siège administratif principal de l'UE et la Commission européenne y siège." },
  { id: "g66", theme: "geographie", question: "Quelle est la ville de France connue pour son festival de cinéma ?", answer: "Cannes, sur la Côte d'Azur, accueille chaque année en mai le Festival International du Film, où la Palme d'Or est décernée. C'est l'un des festivals les plus prestigieux au monde." },
  { id: "g67", theme: "geographie", question: "Quelle rivière traverse la ville de Lyon ?", answer: "Lyon est traversée par deux fleuves : le Rhône et la Saône qui se rejoignent au sud de la ville. Cette confluence donne à Lyon son caractère de ville fluviale et a favorisé son développement commercial." },
  { id: "g68", theme: "geographie", question: "Quel est l'ancien nom romain de Paris ?", answer: "Lutèce (Lutetia Parisiorum). Les Romains fondèrent cette cité gallo-romaine sur l'île de la Cité au 1er siècle av. J.-C. Le nom « Paris » vient de la tribu gauloise des Parisii." },
  { id: "g69", theme: "geographie", question: "Quelle est la région française réputée pour ses fromages et ses volcans ?", answer: "L'Auvergne (Auvergne-Rhône-Alpes), avec ses volcans éteints du Massif central (Puy de Dôme, chaîne des Puys classée UNESCO) et ses fromages : Saint-Nectaire, Cantal, Bleu d'Auvergne." },
  { id: "g70", theme: "geographie", question: "Quelle est la plus grande forêt de France métropolitaine ?", answer: "La forêt des Landes, dans le sud-ouest de la France (Nouvelle-Aquitaine et Occitanie), est la plus grande forêt artificielle d'Europe avec environ 1 million d'hectares de pins maritimes." },
  { id: "g71", theme: "geographie", question: "Qu'est-ce que le Viaduc de Millau ?", answer: "Pont à haubans inauguré en 2004 dans l'Aveyron, c'est le plus haut viaduc du monde (343 m de hauteur maximale). Il enjambe la vallée du Tarn et est une prouesse architecturale mondiale." },
  { id: "g72", theme: "geographie", question: "Quelle est la longueur des côtes françaises ?", answer: "La France possède environ 5 500 km de côtes (métropole), ce qui en fait l'un des pays européens avec le plus grand littoral, entre Manche, Atlantique et Méditerranée." },
  { id: "g73", theme: "geographie", question: "Qu'est-ce que les Pyrénées ?", answer: "Chaîne de montagnes longue de 430 km qui forme la frontière naturelle entre la France et l'Espagne. Le point culminant est le pic d'Aneto (3 404 m, côté espagnol) ou le Vignemale (3 298 m, côté français)." },
  { id: "g74", theme: "geographie", question: "Qu'est-ce que la Camargue ?", answer: "Zone humide et delta du Rhône dans le sud de la France (PACA), classée réserve de biosphère UNESCO. Elle est célèbre pour ses flamants roses, ses chevaux blancs et ses gardians (cow-boys camarguais)." },
  { id: "g75", theme: "geographie", question: "Quelle ville française est connue comme capitale mondiale de la mode ?", answer: "Paris est reconnue comme la capitale mondiale de la mode et du luxe. Elle abrite les grandes maisons de haute couture (Chanel, Dior, Louis Vuitton, Hermès) et accueille deux semaines de la mode par an." },
  { id: "g76", theme: "geographie", question: "Quel est le plus grand port maritime de France ?", answer: "Le Grand Port Maritime de Marseille est le premier port de France et de Méditerranée. Le Havre est le premier port de commerce de la façade atlantique et le deuxième de France." },
  { id: "g77", theme: "geographie", question: "Qu'est-ce que l'île de la Réunion ?", answer: "DROM français situé dans l'océan Indien, à l'est de Madagascar. Connue pour son volcan actif (le Piton de la Fournaise), ses plages et sa cuisine métissée. Sa capitale est Saint-Denis." },
  { id: "g78", theme: "geographie", question: "Qu'est-ce que la Guyane française ?", answer: "DROM situé en Amérique du Sud, entre le Suriname et le Brésil. C'est le plus grand territoire français (83 000 km²). Elle abrite la base spatiale de Kourou d'où sont lancées les fusées Ariane." },
  { id: "g79", theme: "geographie", question: "Qu'est-ce que la Martinique ?", answer: "Île des Antilles françaises (DROM) dans la mer des Caraïbes. Connue pour ses plages, sa montagne Pelée (volcan) et sa culture créole. Sa principale ville est Fort-de-France." },
  { id: "g80", theme: "geographie", question: "Quelle est la région la plus peuplée de France ?", answer: "L'Île-de-France, avec environ 12 millions d'habitants, soit près de 18% de la population française. Elle concentre Paris et sa banlieue, le premier pôle économique de France et d'Europe." },
  { id: "g81", theme: "geographie", question: "Qu'est-ce que les Alpes françaises ?", answer: "Chaîne de montagnes à l'est de la France, frontière naturelle avec l'Italie et la Suisse. Elles abritent le Mont-Blanc (4 808 m), de nombreuses stations de ski et des parcs nationaux (Vanoise, Écrins)." },
  { id: "g82", theme: "geographie", question: "Quelle est la particularité géographique de la France dans l'UE ?", answer: "La France est le seul pays de l'UE présent sur plusieurs continents (Europe, Amérique, Afrique, Océanie) grâce à ses territoires d'outre-mer. Elle possède la 2e plus grande zone économique exclusive maritime au monde." },
  { id: "g83", theme: "geographie", question: "Qu'est-ce que le Louvre ?", answer: "Le musée du Louvre à Paris est le plus grand musée du monde en superficie. Il abrite des chefs-d'œuvre comme la Joconde et la Vénus de Milo. Ancien palais royal, il accueille 9 millions de visiteurs par an." },
  { id: "g84", theme: "geographie", question: "Quelle est la ville natale de Napoléon Bonaparte ?", answer: "Ajaccio, la capitale de la Corse. Napoléon Bonaparte y est né le 15 août 1769, un an après le rattachement de la Corse à la France par le traité de Versailles." },
  { id: "g85", theme: "geographie", question: "Quel est le fleuve qui sépare l'Alsace de l'Allemagne ?", answer: "Le Rhin forme la frontière naturelle entre l'Alsace (France) et le Bade-Wurtemberg (Allemagne). Il prend sa source dans les Alpes suisses et se jette dans la mer du Nord aux Pays-Bas." },
  { id: "g86", theme: "geographie", question: "Qu'est-ce que la Normandie ?", answer: "Région du nord-ouest de la France, baignée par la Manche. Elle est connue pour ses plages du Débarquement (6 juin 1944), ses pommiers (calvados, cidre), le Mont-Saint-Michel et la cathédrale de Rouen." },
  { id: "g87", theme: "geographie", question: "Qu'est-ce que la Bretagne ?", answer: "Région du nord-ouest de France, péninsule entre la Manche et l'Atlantique. Connue pour ses côtes découpées, ses menhirs (Carnac), ses crêpes et galettes, et sa culture celtique préservée." },
  { id: "g88", theme: "geographie", question: "Quelle ville est la 4e ville de France et capitale de l'aéronautique européenne ?", answer: "Toulouse, capitale de l'Occitanie. Surnommée la Ville rose (briques en terre cuite), elle abrite Airbus, le CNES et de nombreux centres de recherche aéronautique et spatiale." },
  { id: "g89", theme: "geographie", question: "Qu'est-ce que le parc national de la Vanoise ?", answer: "Premier parc national de France, créé en 1963 dans les Alpes savoyardes. Il protège une faune remarquable (bouquetins, chamois) et ses glaciers. Il est contigu au parc national du Gran Paradiso en Italie." },
  { id: "g90", theme: "geographie", question: "Qu'est-ce que les châteaux de la Loire ?", answer: "Ensemble de châteaux renaissance construits le long de la Loire par les rois de France (XVe-XVIe siècles). Chambord, Chenonceau, Amboise et Blois en sont les plus célèbres. Ce val est classé UNESCO." },
  { id: "g91", theme: "geographie", question: "Quel est l'aéroport principal de Paris ?", answer: "L'aéroport Charles-de-Gaulle (Roissy-CDG), à 25 km au nord-est de Paris. C'est le premier aéroport de France et le 2e d'Europe en nombre de passagers. Un second aéroport parisien, Orly, se situe au sud." },
  { id: "g92", theme: "geographie", question: "Qu'est-ce que le Canal du Midi ?", answer: "Canal navigable de 240 km reliant la Garonne à la Méditerranée, construit sous Louis XIV au XVIIe siècle. Chef-d'œuvre d'ingénierie, il est classé au patrimoine mondial de l'UNESCO depuis 1996." },
  { id: "g93", theme: "geographie", question: "Qu'est-ce que la Tour Eiffel ?", answer: "Monument emblématique de Paris, construit pour l'Exposition universelle de 1889 par Gustave Eiffel. Haute de 330 mètres, elle est le monument payant le plus visité au monde avec 7 millions de visiteurs par an." },
  { id: "g94", theme: "geographie", question: "Quel est le tunnel sous la Manche ?", answer: "Tunnel ferroviaire de 50 km reliant Folkestone (Angleterre) à Coquelles (France), inauguré en 1994. Il est parcouru par l'Eurostar (Londres-Paris en 2h15) et permet le transport de voitures (Eurotunnel)." },
  { id: "g95", theme: "geographie", question: "Qu'est-ce que la cathédrale Notre-Dame de Paris ?", answer: "Chef-d'œuvre de l'architecture gothique médiévale sur l'île de la Cité, construite entre 1163 et 1345. Gravement endommagée par l'incendie d'avril 2019, elle a été entièrement restaurée et rouverte en décembre 2024." },
  { id: "g96", theme: "geographie", question: "Où se trouve le palais de Versailles ?", answer: "À Versailles, dans les Yvelines, à 20 km au sud-ouest de Paris. Ce palais, résidence de Louis XIV et de la cour royale de 1682 à 1789, est classé au patrimoine mondial de l'UNESCO." },
  { id: "g97", theme: "geographie", question: "Quelle est la particularité de la Polynésie française ?", answer: "Collectivité française d'Outre-Mer dans l'océan Pacifique, composée de 118 îles dont Tahiti. Elle est connue pour ses lagons et récifs coralliens. Sa capitale est Papeete." },
  { id: "g98", theme: "geographie", question: "Qu'est-ce que le réseau TGV en France ?", answer: "Le Train à Grande Vitesse (TGV), inauguré en 1981, est le réseau ferroviaire à grande vitesse français. Il permet de relier Paris à Lyon en 2h, à Marseille en 3h et à Bordeaux en 2h." },
  { id: "g99", theme: "geographie", question: "Quelle ville est surnommée la \"Ville lumière\" ?", answer: "Paris, surnommée ainsi depuis le XVIIe siècle car elle fut l'une des premières villes à s'éclairer à la lanterne publique, et parce qu'elle était le centre des Lumières intellectuelles au XVIIIe siècle." },
  { id: "g100", theme: "geographie", question: "Qu'est-ce que la zone économique exclusive (ZEE) française ?", answer: "La France possède la 2e plus grande ZEE au monde (11,7 millions de km²) grâce à ses territoires ultramarins dans tous les océans. Cette zone lui permet d'exploiter les ressources marines." },
  { id: "g101", theme: "geographie", question: "Qu'est-ce que la Guadeloupe ?", answer: "Archipel français des Antilles (DROM) en mer des Caraïbes. Composée de deux îles principales (Grande-Terre et Basse-Terre) en forme de papillon. Sa capitale est Basse-Terre et son chef-lieu Pointe-à-Pitre." },
  { id: "g102", theme: "geographie", question: "Qu'est-ce que Mayotte ?", answer: "Île française devenue 101e département français en 2011, située dans l'océan Indien entre Madagascar et le Mozambique. Sa population est très jeune et en forte croissance. Sa capitale est Mamoudzou." },
  { id: "g103", theme: "geographie", question: "Quelle est la plus ancienne université de France ?", answer: "L'Université de Paris, fondée au XIIe siècle (vers 1150-1170), aujourd'hui divisée en plusieurs universités (Sorbonne, Paris-I à Paris-XIII). La Sorbonne reste un symbole de l'enseignement supérieur français." },
  { id: "g104", theme: "geographie", question: "Qu'est-ce que l'Arc de Triomphe à Paris ?", answer: "Monument situé au centre de la place de l'Étoile, commandé par Napoléon Ier en 1806 pour commémorer ses victoires. Haut de 50 mètres, il abrite la tombe du Soldat Inconnu depuis 1920." },
  { id: "g105", theme: "geographie", question: "Qu'est-ce que la grotte de Lascaux ?", answer: "Site préhistorique en Dordogne (Nouvelle-Aquitaine) contenant des peintures rupestres datant d'environ 17 000 ans. Classée UNESCO, l'originale est fermée au public ; un fac-similé (Lascaux IV) est visitable." },
  { id: "g106", theme: "geographie", question: "Quelle est la spécialité culinaire de Lyon ?", answer: "Lyon, capitale gastronomique de la France, est connue pour les quenelles de brochet, le boudin, les tripes, les bouchons lyonnais (restaurants typiques) et les grandes maisons comme Paul Bocuse." },
  { id: "g107", theme: "geographie", question: "Qu'est-ce que la Côte d'Azur ?", answer: "Riviera française sur la Méditerranée, de Menton à Cassis. Connue pour son climat, ses plages, Nice, Monaco, Cannes et Saint-Tropez. Elle attire chaque année des millions de touristes du monde entier." },
  { id: "g108", theme: "geographie", question: "Combien de collectivités et territoires d'Outre-Mer (COM-TOM) la France compte-t-elle ?", answer: "La France compte 5 collectivités d'outre-mer (Saint-Martin, Saint-Barthélemy, Saint-Pierre-et-Miquelon, Wallis-et-Futuna, Polynésie française) et 1 pays d'outre-mer (Nouvelle-Calédonie)." },
  { id: "g109", theme: "geographie", question: "Quelle est la ville principale de la région Bretagne ?", answer: "Rennes est la capitale régionale de la Bretagne. Brest est la 2e ville bretonne et un important port militaire. Nantes, bien qu'historiquement bretonne, est aujourd'hui capitale des Pays de la Loire." },
  { id: "g110", theme: "geographie", question: "Qu'est-ce que la Bourgogne-Franche-Comté ?", answer: "Grande région de l'est de la France, connue pour ses vins de Bourgogne (Chablis, Gevrey-Chambertin, Beaune), ses moutardes de Dijon et son patrimoine (hôtel-Dieu de Beaune, abbaye de Cluny)." },
  { id: "g111", theme: "geographie", question: "Qu'est-ce que la Nouvelle-Calédonie ?", answer: "Collectivité française de l'Océanie, à 17 000 km de la métropole. Connue pour ses récifs coralliens (classés UNESCO), sa mine de nickel (3e réserve mondiale) et ses populations mélanésiennes (Kanaks)." },

  // ─── DROITS─────────────────────────────────────────────────────────────────────
  { id: "d01", theme: "droits", question: "En quelle année la loi sur le mariage pour tous a été adoptée ?", answer: "La loi sur le mariage pour tous a été adoptée en France le 23 avril 2013. Elle a permis l'ouverture du mariage et de l'adoption aux couples de même sexe. La loi a été promulguée le 17 mai 2013." },
  { id: "d02", theme: "droits", question: "Quand la peine de mort a-t-elle été abolie en France ?", answer: "La peine de mort a été abolie en France le 9 octobre 1981." },
  { id: "d03", theme: "droits", question: "Quelle loi a aboli la peine de mort en France ?", answer: "L’abolition de la peine de mort a été votée sous la présidence de François Mitterrand et portée par le ministre de la Justice Robert Badinter." },
  { id: "d04", theme: "droits", question: "Pourquoi vote-t-on en démocratie ?", answer: "Le vote est un droit et un devoir civique permettant aux citoyens d’exprimer leurs choix politiques et d’influencer les décisions publiques." },
  { id: "d05", theme: "droits", question: "Qu’est-ce que la Loi Veil et pourquoi est-elle liée à l’IVG en France ?", answer: "La Loi Veil, adoptée en 1975, est la loi qui a légalisé l'interruption volontaire de grossesse (IVG) en France. Proposée par Simone Veil, alors ministre de la Santé, cette loi a permis aux femmes d'accéder légalement à l'avortement dans un cadre médicalisé, marquant un tournant majeur pour les droits des femmes et leur autonomie." },
  { id: "d06", theme: "droits", question: "Pourquoi l’IVG est-elle un sujet d'actualité en 2024 ?", answer: "En mars 2024, la France est devenue le premier pays à graver la liberté de recourir à l’IVG dans sa Constitution. Cette décision vise à garantir ce droit fondamental et à le protéger de toute remise en cause future." },
  { id: "d07", theme: "droits", question: "Pourquoi l’IVG est-elle un sujet d'actualité en janvier 2025 ?", answer: "Le 17 janvier 2025 marque les 50 ans de la loi Veil, adoptée en 1975, qui a légalisé l’IVG en France. Cette date symbolique donne lieu à des commémorations et des débats sur l’évolution des droits des femmes et de la santé publique depuis un demi-siècle." },
  { id: "d08", theme: "droits", question: "Comment est élu le président de la république ?", answer: "Le président est élu par le biais d'un suffrage universel direct. L'élection se déroule en deux tours, et pour être élu, un candidat doit obtenir la majorité absolue des voix. Le droit de vote est accordé aux citoyens français majeurs." },
  { id: "d09", theme: "droits", question: "C'est quoi la Constitution ?", answer: "La Constitution est le texte fondamental qui définit l’organisation et le fonctionnement de l’État. Elle fixe les règles du pouvoir, les droits des citoyens et les principes de la République." },
  { id: "d10", theme: "droits", question: "L'article 49.3 s'applique-t-il devant l'Assemblée nationale et le Sénat ?", answer: "L'article 49.3 de la Constitution ne peut être utilisé que devant l'Assemblée nationale. Il permet au Premier ministre d’engager la responsabilité du gouvernement sur un texte de loi, ce qui entraîne son adoption sans vote, sauf si une motion de censure est déposée et adoptée par 289 députés (majorité absolue)." },
  { id: "d11", theme: "droits", question: "Pendant combien de mois après l’acquisition de la nationalité est-on autorisée à voter ?", answer: "Dès l’inscription sur les listes électorales, généralement dans les mois suivant l’acquisition de la nationalité." },
  { id: "d12", theme: "droits", question: "Quels sont certains droits et devoirs des citoyens français ?", answer: "Les citoyens français ont le droit de voter, de circuler librement, d’accéder à la justice, et à l’éducation. Parmi leurs devoirs figurent le respect des lois, le paiement des impôts, et la participation au jury d’assises si nécessaire." },
  { id: "d13", theme: "droits", question: "Quelle est la loi qui a instauré la semaine de 35 heures en France ?", answer: "La loi Aubry, en 2000." },
  { id: "d14", theme: "droits", question: "Comment s'appelle le système de santé publique en France ?", answer: "La Sécurité Sociale." },
  { id: "d15", theme: "droits", question: "Quel est le principe du droit du sang en matière de nationalité française ?", answer: "L'acquisition de la nationalité française par filiation." },
  { id: "d16", theme: "droits", question: "Quel est l'âge de l’obligation scolaire en France ?", answer: "L'école est obligatoire de 3 à 16 ans en France." },
  { id: "d17", theme: "droits", question: "Citez quelques personnalités françaises célèbres ayant acquis la nationalité française.", answer: "Parmi les personnalités naturalisées, on trouve le chanteur Johnny Hallyday, l’artiste Pablo Picasso, l’actrice Marlène Dietrich, et l’écrivain Milan Kundera." },
  { id: "d18", theme: "droits", question: "Quelle est la première université fondée en France ?", answer: "L'Université de Paris, connue sous le nom de Sorbonne." },
  { id: "d19", theme: "droits", question: "Quelle est l'œuvre littéraire de Victor Hugo plaidant contre la peine de mort ?", answer: "Le Dernier Jour d'un condamné." },
  { id: "d20", theme: "droits", question: "À quel âge peut-on voter en France ?", answer: "À 18 ans. Le droit de vote est universel : tout citoyen français majeur peut voter, sans distinction de sexe, d'origine ou de condition sociale." },
  { id: "d21", theme: "droits", question: "Quels sont les principaux devoirs d'un citoyen français ?", answer: "Respecter les lois, payer ses impôts, participer aux jurys d'assises si convoqué, respecter la laïcité et contribuer à la vie de la communauté nationale." },
  { id: "d22", theme: "droits", question: "Qu'est-ce que le droit d'asile en France ?", answer: "Tout étranger persécuté dans son pays pour des raisons politiques, religieuses ou sociales peut demander protection en France. Ce droit est garanti par la Constitution de 1958." },
  { id: "d23", theme: "droits", question: "Qu'est-ce que la protection sociale française ?", answer: "Système de couverture des risques sociaux : maladie, retraite, chômage, maternité. Il est financé par les cotisations des salariés et des employeurs." },
  { id: "d24", theme: "droits", question: "Qu'est-ce que la Journée défense et citoyenneté (JDC) ?", answer: "Journée obligatoire pour tous les jeunes Français de 17 à 25 ans. Elle informe sur la défense nationale, la citoyenneté et teste le niveau de lecture." },
  { id: "d25", theme: "droits", question: "Qu'est-ce que le droit à l'éducation en France ?", answer: "L'école est obligatoire de 3 à 16 ans et gratuite dans les établissements publics. C'est un droit fondamental garanti par l'État pour tous les enfants sur le territoire." },
  { id: "d26", theme: "droits", question: "Qu'est-ce que le SMIC ?", answer: "Le Salaire Minimum Interprofessionnel de Croissance. C'est le salaire horaire minimum légal en dessous duquel aucun employeur ne peut rémunérer un salarié." },
  { id: "d27", theme: "droits", question: "Qu'est-ce que la liberté de la presse en France ?", answer: "Droit fondamental garanti par la loi de 1881. Les journalistes peuvent informer librement, sans censure préalable de l'État." },
  { id: "d28", theme: "droits", question: "Pourquoi est-il important de payer ses impôts en France ?", answer: "Les impôts financent les services publics : école, hôpital, sécurité, routes. C'est un devoir civique qui permet le fonctionnement de la solidarité nationale." },
  { id: "d29", theme: "droits", question: "Qu'est-ce que la présomption d'innocence en France ?", answer: "Toute personne accusée est présumée innocente jusqu'à ce que sa culpabilité soit établie par un tribunal. C'est un droit fondamental garanti par la loi." },
  { id: "d30", theme: "droits", question: "Qu'est-ce que la liberté d'association en France ?", answer: "Garantie par la loi de 1901, toute personne peut créer librement une association sans autorisation préalable. C'est un pilier de la vie civique française." },
  { id: "d31", theme: "droits", question: "Qu'est-ce que le droit du travail en France ?", answer: "Ensemble des lois qui régissent les relations entre employeurs et salariés. Il protège les travailleurs via le Code du travail, le SMIC, les congés payés et les syndicats." },
  { id: "d32", theme: "droits", question: "Qu'est-ce que la durée légale du travail en France ?", answer: "La durée légale est de 35 heures par semaine depuis la loi Aubry de 2000. Les heures supplémentaires au-delà sont majorées et encadrées par la loi." },
  { id: "d33", theme: "droits", question: "Qu'est-ce que les congés payés en France ?", answer: "Tout salarié a droit à 5 semaines de congés payés par an minimum, soit 2,5 jours par mois travaillé. C'est un droit acquis depuis le Front populaire en 1936." },
  { id: "d34", theme: "droits", question: "Qu'est-ce que l'assurance chômage en France ?", answer: "Système qui indemnise les salariés ayant perdu involontairement leur emploi. Il est géré par France Travail (ex-Pôle Emploi) et financé par les cotisations patronales et salariales." },
  { id: "d35", theme: "droits", question: "Qu'est-ce que le RSA (Revenu de Solidarité Active) ?", answer: "Aide sociale versée aux personnes sans ressources ou aux travailleurs à très faibles revenus. Il garantit un revenu minimum pour permettre à chacun de vivre dignement." },
  { id: "d36", theme: "droits", question: "Qu'est-ce que la carte Vitale en France ?", answer: "Carte d'identité de l'assuré social, elle permet d'être remboursé plus rapidement par l'Assurance Maladie après une consultation médicale ou l'achat de médicaments." },
  { id: "d37", theme: "droits", question: "Qu'est-ce que le droit au logement (loi DALO) ?", answer: "La loi DALO (2007) garantit le droit à un logement décent aux personnes qui ne peuvent y accéder seules. L'État doit prendre en charge les demandeurs prioritaires." },
  { id: "d38", theme: "droits", question: "Qu'est-ce que le PACS en France ?", answer: "Le Pacte Civil de Solidarité est un contrat conclu entre deux personnes majeures pour organiser leur vie commune. Il ouvre des droits fiscaux et sociaux similaires au mariage." },
  { id: "d39", theme: "droits", question: "Quels sont les droits et libertés garantis par la Constitution française ?", answer: "La liberté, l'égalité, la dignité humaine, la liberté de conscience, le droit au travail, à la santé, à l'éducation, garantis par la Constitution de 1958 et son Préambule." },
  { id: "d40", theme: "droits", question: "Qu'est-ce que la loi de 1905 garantit aux citoyens ?", answer: "La loi de séparation des Églises et de l'État garantit la liberté de conscience et de culte : chacun est libre de croire ou non, sans que l'État n'intervienne dans la sphère religieuse." },
  { id: "d41", theme: "droits", question: "Qu'est-ce que la liberté syndicale en France ?", answer: "Tout travailleur a le droit d'adhérer au syndicat de son choix et d'exercer une activité syndicale. Ce droit est garanti par le Préambule de la Constitution de 1946." },
  { id: "d42", theme: "droits", question: "Qu'est-ce que le droit de grève en France ?", answer: "Droit constitutionnel permettant aux salariés de cesser collectivement le travail pour défendre leurs intérêts professionnels. Il s'exerce dans le cadre fixé par la loi." },
  { id: "d43", theme: "droits", question: "Qu'est-ce que le CPF (Compte Personnel de Formation) ?", answer: "Dispositif permettant à tout actif de cumuler des heures de formation tout au long de sa carrière professionnelle, financées par les cotisations patronales." },
  { id: "d44", theme: "droits", question: "Qu'est-ce que l'apprentissage en France ?", answer: "Contrat de travail en alternance permettant à un jeune de se former dans un centre de formation (CFA) tout en travaillant en entreprise. Il débouche sur un diplôme reconnu." },
  { id: "d45", theme: "droits", question: "Qu'est-ce que l'aide juridictionnelle en France ?", answer: "Dispositif permettant aux personnes à faibles ressources d'accéder à la justice en bénéficiant gratuitement (totalement ou partiellement) d'un avocat pris en charge par l'État." },
  { id: "d46", theme: "droits", question: "Qu'est-ce que le droit à un procès équitable ?", answer: "Garantie que toute personne jugée ait accès à un tribunal impartial, puisse se défendre avec un avocat et bénéficie de la présomption d'innocence. C'est un droit fondamental en France." },
  { id: "d47", theme: "droits", question: "Qu'est-ce que la naturalisation par décret en France ?", answer: "Procédure par laquelle un étranger peut acquérir la nationalité française, sous conditions : 5 ans de résidence régulière, maîtrise du français, intégration républicaine et absence de condamnation." },
  { id: "d48", theme: "droits", question: "Qu'est-ce que le droit du sol en France ?", answer: "Principe selon lequel un enfant né en France de parents étrangers peut, sous conditions, acquérir la nationalité française. La France combine droit du sol et droit du sang." },
  { id: "d49", theme: "droits", question: "Qu'est-ce que la protection de l'enfance en France ?", answer: "Ensemble de dispositifs (Aide Sociale à l'Enfance, signalement, placement) visant à protéger les mineurs en danger. La maltraitance doit être signalée aux autorités." },
  { id: "d50", theme: "droits", question: "Qu'est-ce que le mariage civil en France ?", answer: "Le mariage civil est le seul reconnu légalement en France. Il est célébré en mairie devant un officier d'état civil. Le mariage religieux n'a aucune valeur légale sans le mariage civil." },
  { id: "d51", theme: "droits", question: "Qu'est-ce que la loi contre les violences conjugales en France ?", answer: "La France dispose de lois très protectrices pour les victimes de violences conjugales, notamment l'ordonnance de protection, le bracelet anti-rapprochement et des sanctions pénales renforcées." },
  { id: "d52", theme: "droits", question: "Qu'est-ce que le baccalauréat en France ?", answer: "Diplôme national qui sanctionne la fin des études secondaires et permet l'accès à l'enseignement supérieur. Créé par Napoléon en 1808, il existe en filières générale, technologique et professionnelle." },
  { id: "d53", theme: "droits", question: "Qu'est-ce que la TVA en France ?", answer: "La Taxe sur la Valeur Ajoutée est un impôt indirect prélevé à chaque étape de la production et de la vente. Le taux normal est de 20 %, avec des taux réduits pour certains biens essentiels." },
  { id: "d54", theme: "droits", question: "Qu'est-ce que l'impôt sur le revenu en France ?", answer: "Impôt prélevé sur les revenus des personnes physiques. Il est progressif : plus on gagne, plus on paie. Il est déclaré annuellement et finance une partie du budget de l'État." },
  { id: "d55", theme: "droits", question: "Qu'est-ce que la loi Badinter (1981) ?", answer: "Loi présentée par Robert Badinter, garde des Sceaux, qui a aboli la peine de mort en France le 9 octobre 1981, sous la présidence de François Mitterrand." },
  { id: "d56", theme: "droits", question: "Qu'est-ce que l'obligation vaccinale en France ?", answer: "Certains vaccins sont obligatoires en France pour les nourrissons (11 vaccins depuis 2018). Cette obligation vise à protéger la collectivité contre les maladies graves." },
  { id: "d57", theme: "droits", question: "Qu'est-ce que la retraite à taux plein en France ?", answer: "Pour bénéficier d'une retraite complète, un salarié doit avoir cotisé un nombre suffisant de trimestres (environ 172 trimestres) et atteindre l'âge légal fixé par la loi." },
  { id: "d58", theme: "droits", question: "Qu'est-ce que la mutuelle complémentaire santé ?", answer: "Organisme d'assurance qui rembourse les frais médicaux non couverts par la Sécurité sociale. L'employeur est obligé de participer à la mutuelle de ses salariés depuis 2016." },
  { id: "d59", theme: "droits", question: "Qu'est-ce que la loi Claeys-Leonetti sur la fin de vie ?", answer: "Loi de 2016 qui garantit le droit à une sédation profonde et continue jusqu'au décès pour les patients en fin de vie. Elle renforce les droits des malades tout en interdisant l'euthanasie active." },
  { id: "d60", theme: "droits", question: "Qu'est-ce que le RGPD (protection des données) en France ?", answer: "Règlement Général sur la Protection des Données, en vigueur depuis 2018, qui protège les données personnelles des citoyens européens. La CNIL veille à son respect en France." },
  { id: "d61", theme: "droits", question: "Qu'est-ce que la loi sur la parité en politique (2000) ?", answer: "La loi Génisson de 2000 oblige les partis politiques à présenter autant de candidates que de candidats aux élections, sous peine de sanctions financières. Elle vise l'égalité femmes-hommes en politique." },
  { id: "d62", theme: "droits", question: "Qu'est-ce que l'accessibilité universelle en France ?", answer: "Obligation légale de rendre les bâtiments, transports et services accessibles à toutes les personnes, notamment celles en situation de handicap. La France vise une société inclusive." },
  { id: "d63", theme: "droits", question: "Qu'est-ce que le contrat de travail à durée indéterminée (CDI) ?", answer: "Le CDI est la forme normale et générale de la relation de travail en France. Il n'a pas de date de fin et offre une plus grande stabilité au salarié par rapport au CDD." },
  { id: "d64", theme: "droits", question: "Qu'est-ce que la médiation en France ?", answer: "Mode alternatif de résolution des conflits où un tiers neutre (médiateur) aide les parties à trouver un accord amiable, sans passer par un tribunal. Elle est encouragée par la loi." },
  { id: "d65", theme: "droits", question: "Qu'est-ce que l'allocations familiales en France ?", answer: "Aides versées par la CAF aux familles ayant au moins 2 enfants à charge de moins de 20 ans. Elles font partie du système de protection sociale familiale français." },
  { id: "d66", theme: "droits", question: "Qu'est-ce que la garde à vue en France ?", answer: "Mesure policière permettant de retenir une personne suspectée pendant 24 heures (renouvelable). La personne gardée à vue a le droit d'être assistée d'un avocat dès le début de la mesure." },
  { id: "d67", theme: "droits", question: "Qu'est-ce que le principe de non-discrimination à l'emploi ?", answer: "En France, il est interdit de refuser un emploi ou d'imposer des conditions différentes en raison de l'origine, du sexe, de la religion ou du handicap. La discrimination à l'emploi est un délit pénal." },
  { id: "d68", theme: "droits", question: "Qu'est-ce que la reconnaissance du statut de réfugié en France ?", answer: "L'OFPRA (Office Français de Protection des Réfugiés) instruit les demandes d'asile. Le statut de réfugié est accordé aux personnes persécutées, conformément à la Convention de Genève de 1951." },
  { id: "d69", theme: "droits", question: "Qu'est-ce que le droit à la santé en France ?", answer: "Tout résident en France a accès aux soins médicaux via la Sécurité sociale. La Couverture Maladie Universelle (CMU-C) protège les personnes sans ressources suffisantes." },
  { id: "d70", theme: "droits", question: "Qu'est-ce que le Conseil Supérieur de la Magistrature (CSM) ?", answer: "Instance constitutionnelle qui garantit l'indépendance de la justice. Il gère la carrière des magistrats et donne son avis sur les nominations aux postes judiciaires importants." },
  { id: "d71", theme: "droits", question: "Qu'est-ce que le jury populaire en France ?", answer: "Citoyens tirés au sort qui participent aux décisions des cours d'assises (crimes les plus graves). Cette institution traduit la participation directe des citoyens à la justice." },
  { id: "d72", theme: "droits", question: "Qu'est-ce que la liberté de conscience en France ?", answer: "Droit fondamental de penser librement, de choisir ou de rejeter toute croyance religieuse ou philosophique. En France, l'État ne peut contraindre personne dans ses convictions intimes." },
  { id: "d73", theme: "droits", question: "Qu'est-ce que le Défenseur des droits ?", answer: "Autorité indépendante créée en 2011 qui défend les droits des citoyens face aux administrations, lutte contre les discriminations et promeut les droits de l'enfant." },
  { id: "d74", theme: "droits", question: "Qu'est-ce que la loi sur la liberté d'association de 1901 ?", answer: "Cette loi fondatrice permet à toute personne de créer librement une association à but non lucratif, sans autorisation préalable. Elle est le fondement de la vie associative française." },
  { id: "d75", theme: "droits", question: "Qu'est-ce que le vote secret en France ?", answer: "Principe fondamental selon lequel le choix électoral de chaque citoyen est protégé. L'isoloir garantit que nul ne peut être contraint ou observé lors de son vote." },
  { id: "d76", theme: "droits", question: "Qu'est-ce que la procédure de demande de nationalité française ?", answer: "Elle comprend le dépôt d'un dossier en préfecture, un entretien d'assimilation, une enquête de moralité et la signature d'une charte des droits et devoirs du citoyen français." },
  { id: "d77", theme: "droits", question: "Qu'est-ce que la Charte des droits et devoirs du citoyen français ?", answer: "Document signé lors de la cérémonie de naturalisation, par lequel le futur citoyen s'engage à respecter les principes et valeurs de la République française." },
  { id: "d78", theme: "droits", question: "Qu'est-ce que l'état civil en France ?", answer: "Service municipal qui enregistre les actes fondamentaux de la vie d'une personne : naissance, mariage, divorce, décès. Ces actes ont une valeur juridique officielle." },
  { id: "d79", theme: "droits", question: "Qu'est-ce que la laïcité dans les services publics ?", answer: "Les agents de la fonction publique doivent respecter une stricte neutralité religieuse dans l'exercice de leurs fonctions. Ils ne peuvent exprimer leurs convictions religieuses au travail." },
  { id: "d80", theme: "droits", question: "Qu'est-ce que le permis de conduire en France ?", answer: "Document obligatoire pour conduire un véhicule à moteur. Le permis B (voiture) s'obtient dès 17 ans avec l'accompagnement anticipé à la conduite (AAC). La conduite sans permis est un délit." },
  { id: "d81", theme: "droits", question: "Qu'est-ce que la Caisse d'Allocations Familiales (CAF) ?", answer: "Organisme de Sécurité sociale qui verse de nombreuses aides : allocations familiales, aide au logement (APL), RSA, etc. Elle accompagne les familles et les personnes en difficulté." },
  { id: "d82", theme: "droits", question: "Qu'est-ce que le congé maternité en France ?", answer: "La salariée enceinte a droit à un congé maternité rémunéré par la Sécurité sociale : 16 semaines pour le premier enfant. Son emploi est protégé pendant cette période." },
  { id: "d83", theme: "droits", question: "Qu'est-ce que le congé paternité en France ?", answer: "Le père (ou co-parent) a droit à 25 jours de congé après la naissance de son enfant, dont 7 jours obligatoires, rémunérés par la Sécurité sociale." },
  { id: "d84", theme: "droits", question: "Qu'est-ce que le droit à la retraite en France ?", answer: "Tout travailleur cotisant à la Sécurité sociale acquiert des droits à la retraite. L'âge légal de départ est fixé à 64 ans depuis la réforme de 2023." },
  { id: "d85", theme: "droits", question: "Qu'est-ce que la médecine préventive en France ?", answer: "L'État encourage la prévention via des dépistages gratuits (cancer du sein, colorectal), des vaccinations et des bilans de santé. La prévention réduit les coûts de santé à long terme." },
  { id: "d86", theme: "droits", question: "Qu'est-ce que la lutte contre le harcèlement scolaire en France ?", answer: "La France a renforcé les lois contre le harcèlement scolaire et le cyberharcèlement. Des dispositifs comme le 3018 (numéro national) permettent aux victimes de signaler les situations." },
  { id: "d87", theme: "droits", question: "Qu'est-ce que l'allocation adulte handicapé (AAH) ?", answer: "Aide financière versée par la CAF aux personnes en situation de handicap qui ne peuvent pas ou peu travailler. Elle garantit un revenu minimum et favorise leur autonomie." },
  { id: "d88", theme: "droits", question: "Qu'est-ce que le service civique en France ?", answer: "Engagement volontaire de 6 à 12 mois ouvert aux jeunes de 16 à 25 ans pour effectuer une mission d'intérêt général (santé, éducation, environnement). Il est indemnisé par l'État." },
  { id: "d89", theme: "droits", question: "Qu'est-ce que la protection contre le licenciement abusif en France ?", answer: "Un salarié en CDI ne peut être licencié sans motif réel et sérieux. En cas de licenciement abusif, le salarié peut saisir le Conseil de Prud'hommes pour obtenir des dommages et intérêts." },
  { id: "d90", theme: "droits", question: "Qu'est-ce que le bulletin de salaire (fiche de paie) ?", answer: "Document remis par l'employeur à chaque salarié mentionnant le salaire brut, les cotisations sociales et le salaire net. Il est obligatoire et constitue une preuve des droits acquis." },
  { id: "d91", theme: "droits", question: "Qu'est-ce que le Comité Social et Économique (CSE) ?", answer: "Instance représentative des salariés dans les entreprises de plus de 11 employés. Il représente les intérêts des travailleurs et participe aux décisions concernant les conditions de travail." },
  { id: "d92", theme: "droits", question: "Qu'est-ce que la taxe foncière en France ?", answer: "Impôt local annuel payé par les propriétaires de biens immobiliers (maisons, appartements, terrains). Elle finance les collectivités locales (communes, départements)." },
  { id: "d93", theme: "droits", question: "Qu'est-ce que les droits des locataires en France ?", answer: "Un locataire bénéficie de nombreuses protections : durée minimale du bail, encadrement des loyers, protection contre les expulsions abusives et droit à un logement décent." },
  { id: "d94", theme: "droits", question: "Qu'est-ce que le principe d'égalité devant la justice ?", answer: "Tout citoyen a le droit d'être jugé par les mêmes règles de droit, sans distinction de rang, fortune ou origine. En France, nul n'est au-dessus des lois, y compris les personnalités politiques." },
  { id: "d95", theme: "droits", question: "Qu'est-ce que la protection des données personnelles (RGPD) ?", answer: "Le Règlement Général sur la Protection des Données (2018) oblige les entreprises à protéger les données personnelles des citoyens européens. La CNIL française veille à son application et peut infliger de lourdes amendes." },
  { id: "d96", theme: "droits", question: "Qu'est-ce que l'obligation d'instruction en France ?", answer: "L'instruction est obligatoire pour tous les enfants résidant en France, de 3 à 16 ans. Elle peut se faire à l'école (publique ou privée) ou à domicile, sous contrôle de l'État." },
  { id: "d97", theme: "droits", question: "Qu'est-ce que la liberté de circulation en France ?", answer: "Tout citoyen français a le droit de se déplacer librement sur le territoire national et d'en sortir. Ce droit fondamental est garanti par la Constitution et peut être restreint exceptionnellement (état d'urgence)." },
  { id: "d98", theme: "droits", question: "Qu'est-ce que le droit à la vie privée en France ?", answer: "La vie privée est protégée par l'article 9 du Code civil et par la CEDH. Le secret des correspondances, le droit à l'image et la protection du domicile sont des aspects fondamentaux de ce droit." },
  { id: "d99", theme: "droits", question: "Qu'est-ce que le droit de vote par procuration en France ?", answer: "Un électeur empêché peut déléguer son vote à un autre électeur inscrit dans la même commune. La procuration peut être établie en commissariat, gendarmerie ou via la plateforme en ligne Maprocuration.gouv.fr." },
  { id: "d100", theme: "droits", question: "Qu'est-ce que la médecine de travail en France ?", answer: "Service médical obligatoire dans les entreprises, qui assure le suivi de la santé des salariés, prévient les risques professionnels et adapte les postes de travail aux capacités des travailleurs." },
  { id: "d101", theme: "droits", question: "Qu'est-ce que l'accès aux soins d'urgence en France ?", answer: "Toute personne en France a droit aux soins d'urgence vitaux, indépendamment de sa situation administrative ou financière. Le SAMU (15) coordonne les secours médicaux d'urgence 24h/24." },
  { id: "d102", theme: "droits", question: "Qu'est-ce que la reconnaissance du handicap en France ?", answer: "La MDPH (Maison Départementale des Personnes Handicapées) évalue le handicap et attribue des droits : AAH, RQTH, carte mobilité inclusion. La France vise une société inclusive pour les 12 millions de personnes handicapées." },
  { id: "d103", theme: "droits", question: "Qu'est-ce que le principe de gratuité de l'école publique en France ?", answer: "L'enseignement dans les écoles, collèges et lycées publics est gratuit pour tous. L'État finance les établissements et rémunère les enseignants. Seuls certains matériels scolaires restent à la charge des familles." },
  { id: "d104", theme: "droits", question: "Qu'est-ce que l'aide sociale à l'hébergement en France ?", answer: "Dispositif permettant à des personnes âgées, handicapées ou en difficulté sociale d'obtenir une aide financière pour payer leurs frais d'hébergement en établissement ou à domicile." },
  { id: "d105", theme: "droits", question: "Qu'est-ce que le droit au respect de la dignité en prison ?", answer: "Même les personnes incarcérées conservent leurs droits fondamentaux : droit à des conditions de détention décentes, accès aux soins, à la formation et aux visites. Le Contrôleur général des lieux de privation de liberté veille à ces conditions." },
  { id: "d106", theme: "droits", question: "Qu'est-ce que la protection des lanceurs d'alerte en France ?", answer: "La loi Sapin II (2016) et la loi Waserman (2022) protègent les personnes qui signalent des faits illicites ou des dangers. Les lanceurs d'alerte bénéficient d'une protection contre les représailles de leur employeur." },
  { id: "d107", theme: "droits", question: "Qu'est-ce que le droit à l'alimentation digne en France ?", answer: "L'accès à une alimentation suffisante et de qualité est un droit fondamental. Des associations comme les Restos du Cœur, les Banques alimentaires et le Secours populaire luttent contre la précarité alimentaire." },
  { id: "d108", theme: "droits", question: "Qu'est-ce que la reconnaissance du statut d'apatride en France ?", answer: "Une personne sans nationalité reconnue par aucun État peut obtenir le statut d'apatride en France via l'OFPRA. Ce statut lui confère des droits similaires à ceux d'un réfugié et un titre de voyage." },
  { id: "d109", theme: "droits", question: "Qu'est-ce que le devoir de discrétion des fonctionnaires ?", answer: "Les agents publics sont soumis à une obligation de réserve et de discrétion professionnelle sur les informations dont ils ont connaissance dans l'exercice de leurs fonctions. La violation est une faute disciplinaire." },
  { id: "d110", theme: "droits", question: "Qu'est-ce que le droit à la formation continue en France ?", answer: "Tout salarié dispose d'un Compte Personnel de Formation (CPF) alimenté en heures chaque année. Il peut l'utiliser pour financer des formations tout au long de sa vie professionnelle, favorisant l'évolution de carrière." },
  { id: "d111", theme: "droits", question: "Qu'est-ce que la médiation familiale en France ?", answer: "Service permettant aux familles en conflit (divorce, séparation, garde d'enfants) de trouver des solutions amiables avec l'aide d'un médiateur professionnel. Elle évite le recours aux tribunaux et favorise le dialogue." },

];

export type Rating = "connais" | "hesite" | "connais_pas";
